{
  "name": "Finmo",
  "description": "Seu mentor financeiro pessoal baseado na regra 50/30/20. Organize seus gastos em Meticais, construa sua reserva de emergência e receba conselhos pragmáticos impulsionados por IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum CategoryType {
  NEED = 'NEED',      // 50%
  WANT = 'WANT',      // 30%
  SAVING = 'SAVING'   // 20%
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  category: CategoryType;
  subcategory: string;
  date: string;
}

export interface BudgetStats {
  income: number;
  needs: number;
  wants: number;
  savings: number;
  totalSpent: number;
}

export interface AIAdvice {
  status: 'good' | 'warning' | 'critical';
  message: string;
  recommendations: string[];
}

import { CategoryType } from './types';

export const CURRENCY = 'MT';

export const CATEGORY_LABELS = {
  [CategoryType.NEED]: 'Necessidades Básicas (50%)',
  [CategoryType.WANT]: 'Desejos Pessoais (30%)',
  [CategoryType.SAVING]: 'Investimentos/Reserva (20%)'
};

export const CATEGORY_COLORS = {
  [CategoryType.NEED]: '#3b82f6', // blue-500
  [CategoryType.WANT]: '#a855f7', // purple-500
  [CategoryType.SAVING]: '#10b981' // emerald-500
};

export const formatCurrency = (amount: number): string => {
  return new Intl.NumberFormat('pt-MZ', {
    style: 'currency',
    currency: 'MZN',
  }).format(amount).replace('MZN', CURRENCY);
};

import { GoogleGenAI, Type } from "@google/genai";
import { Transaction, CategoryType, BudgetStats } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getFinancialAdvice = async (
  stats: BudgetStats,
  transactions: Transaction[],
  income: number
) => {
  const prompt = `
    Atue como Finmo, um mentor financeiro especializado na regra 50/30/20. 
    Analise os seguintes dados financeiros do usuário (Moeda: Metical - MT):

    Renda Mensal: ${income} MT
    Gastos em Necessidades (Meta 50%): ${stats.needs} MT (${((stats.needs / income) * 100).toFixed(1)}%)
    Gastos em Desejos (Meta 30%): ${stats.wants} MT (${((stats.wants / income) * 100).toFixed(1)}%)
    Investimentos/Reserva (Meta 20%): ${stats.savings} MT (${((stats.savings / income) * 100).toFixed(1)}%)

    Lista de transações recentes:
    ${transactions.slice(0, 10).map(t => `- ${t.description}: ${t.amount} MT (${t.category})`).join('\n')}

    Sua resposta deve ser em JSON seguindo este esquema:
    {
      "status": "good" | "warning" | "critical",
      "message": "Uma mensagem curta, pragmática e incentivadora.",
      "recommendations": ["Recomendação 1", "Recomendação 2", "Recomendação 3"]
    }

    Regras:
    1. Se os gastos em Desejos (Wants) superarem 30%, identifique cortes agressivos.
    2. Priorize SEMPRE a Reserva de Emergência (Savings).
    3. Seja direto e analítico.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            message: { type: Type.STRING },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["status", "message", "recommendations"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Erro ao obter conselho da IA:", error);
    return {
      status: 'warning',
      message: 'Não consegui analisar seus dados agora, mas lembre-se de manter seus desejos abaixo de 30%.',
      recommendations: ['Revise seus gastos manuais', 'Mantenha o foco na reserva']
    };
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PlusIcon, 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice } from './types';
import { CURRENCY, CATEGORY_LABELS, CATEGORY_COLORS, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [income, setIncome] = useState<number>(30000);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState<CategoryType>(CategoryType.NEED);
  const [aiAdvice, setAiAdvice] = useState<AIAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);

  // Statistics calculation
  const stats = useMemo<BudgetStats>(() => {
    const initialStats = { needs: 0, wants: 0, savings: 0, totalSpent: 0, income };
    return transactions.reduce((acc, t) => {
      if (t.category === CategoryType.NEED) acc.needs += t.amount;
      if (t.category === CategoryType.WANT) acc.wants += t.amount;
      if (t.category === CategoryType.SAVING) acc.savings += t.amount;
      acc.totalSpent += t.amount;
      return acc;
    }, initialStats);
  }, [transactions, income]);

  const chartData = [
    { name: 'Necessidades', real: stats.needs, target: income * 0.5, color: CATEGORY_COLORS[CategoryType.NEED] },
    { name: 'Desejos', real: stats.wants, target: income * 0.3, color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', real: stats.savings, target: income * 0.2, color: CATEGORY_COLORS[CategoryType.SAVING] },
  ];

  const pieData = [
    { name: 'Necessidades', value: stats.needs, color: CATEGORY_COLORS[CategoryType.NEED] },
    { name: 'Desejos', value: stats.wants, color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', value: stats.savings, color: CATEGORY_COLORS[CategoryType.SAVING] },
    { name: 'Disponível', value: Math.max(0, income - stats.totalSpent), color: '#334155' },
  ];

  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    const newTransaction: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description,
      amount: parseFloat(amount),
      category,
      subcategory: 'Geral',
      date: new Date().toISOString(),
    };

    setTransactions([newTransaction, ...transactions]);
    setDescription('');
    setAmount('');
  };

  const removeTransaction = (id: string) => {
    setTransactions(transactions.filter(t => t.id !== id));
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, income);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      {/* Header */}
      <header className="sticky top-0 z-50 glass border-b border-slate-800 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-500 p-2 rounded-xl">
            <WalletIcon className="w-6 h-6 text-slate-900" />
          </div>
          <h1 className="text-2xl font-bold tracking-tight">Finmo</h1>
        </div>
        <div className="flex items-center gap-4">
          <div className="text-right hidden sm:block">
            <p className="text-xs text-slate-400">Renda Mensal</p>
            <input 
              type="number" 
              value={income} 
              onChange={(e) => setIncome(Number(e.target.value))}
              className="bg-transparent text-right font-bold text-emerald-400 focus:outline-none w-24"
            />
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Dashboard Stats */}
        <div className="lg:col-span-8 space-y-8">

          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="glass p-6 rounded-3xl space-y-2 border-l-4 border-blue-500">
              <div className="flex justify-between items-start">
                <p className="text-slate-400 text-sm">Necessidades</p>
                <div className="bg-blue-500/10 p-2 rounded-lg"><CreditCardIcon className="w-4 h-4 text-blue-500" /></div>
              </div>
              <p className="text-xl font-bold">{formatCurrency(stats.needs)}</p>
              <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
                <div 
                  className="bg-blue-500 h-full transition-all duration-500" 
                  style={{ width: `${Math.min(100, (stats.needs / (income * 0.5)) * 100)}%` }}
                />
              </div>
              <p className="text-[10px] text-slate-500">Meta: {formatCurrency(income * 0.5)}</p>
            </div>

            <div className="glass p-6 rounded-3xl space-y-2 border-l-4 border-purple-500">
              <div className="flex justify-between items-start">
                <p className="text-slate-400 text-sm">Desejos</p>
                <div className="bg-purple-500/10 p-2 rounded-lg"><PieChartIcon className="w-4 h-4 text-purple-500" /></div>
              </div>
              <p className="text-xl font-bold">{formatCurrency(stats.wants)}</p>
              <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
                <div 
                  className="bg-purple-500 h-full transition-all duration-500" 
                  style={{ width: `${Math.min(100, (stats.wants / (income * 0.3)) * 100)}%` }}
                />
              </div>
              <p className="text-[10px] text-slate-500">Meta: {formatCurrency(income * 0.3)}</p>
            </div>

            <div className="glass p-6 rounded-3xl space-y-2 border-l-4 border-emerald-500">
              <div className="flex justify-between items-start">
                <p className="text-slate-400 text-sm">Reserva</p>
                <div className="bg-emerald-500/10 p-2 rounded-lg"><TrendingUpIcon className="w-4 h-4 text-emerald-500" /></div>
              </div>
              <p className="text-xl font-bold">{formatCurrency(stats.savings)}</p>
              <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
                <div 
                  className="bg-emerald-500 h-full transition-all duration-500" 
                  style={{ width: `${Math.min(100, (stats.savings / (income * 0.2)) * 100)}%` }}
                />
              </div>
              <p className="text-[10px] text-slate-500">Meta: {formatCurrency(income * 0.2)}</p>
            </div>
          </div>

          {/* Charts Section */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="glass p-6 rounded-3xl">
              <h3 className="text-lg font-semibold mb-6 flex items-center gap-2">
                <TrendingUpIcon className="w-5 h-5 text-emerald-400" />
                Real vs Meta
              </h3>
              <div className="h-64 w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
                    <XAxis dataKey="name" stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                    <YAxis stroke="#64748b" fontSize={10} tickLine={false} axisLine={false} />
                    <Tooltip 
                      contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px' }}
                      itemStyle={{ fontSize: '12px' }}
                    />
                    <Bar dataKey="real" radius={[4, 4, 0, 0]} barSize={32}>
                      {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} />
                      ))}
                    </Bar>
                    <Bar dataKey="target" fill="#334155" radius={[4, 4, 0, 0]} barSize={10} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="glass p-6 rounded-3xl">
              <h3 className="text-lg font-semibold mb-6 flex items-center gap-2">
                <PieChartIcon className="w-5 h-5 text-emerald-400" />
                Alocação Atual
              </h3>
              <div className="h-64 w-full relative">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={pieData}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="value"
                    >
                      {pieData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <span className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Saldo</span>
                  <span className="text-lg font-bold">{formatCurrency(Math.max(0, income - stats.totalSpent))}</span>
                </div>
              </div>
            </div>
          </div>

          {/* AI Mentorship Section */}
          <div className="relative overflow-hidden group">
            <div className="absolute -inset-1 bg-gradient-to-r from-emerald-500 to-blue-500 rounded-3xl blur opacity-25 group-hover:opacity-40 transition duration-1000"></div>
            <div className="relative glass p-8 rounded-3xl space-y-6">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <div className="bg-emerald-500/20 p-3 rounded-2xl">
                    <SparklesIcon className="w-6 h-6 text-emerald-400" />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold">Conselheiro Finmo</h2>
                    <p className="text-sm text-slate-400">Análise inteligente dos seus hábitos</p>
                  </div>
                </div>
                <button 
                  onClick={getMentorship}
                  disabled={loadingAdvice || transactions.length === 0}
                  className="bg-emerald-500 hover:bg-emerald-600 disabled:opacity-50 text-slate-950 font-bold py-2 px-6 rounded-xl transition-all flex items-center gap-2"
                >
                  {loadingAdvice ? "Analisando..." : "Pedir Mentoria"}
                </button>
              </div>

              {aiAdvice ? (
                <div className={`p-6 rounded-2xl border-l-4 animate-in fade-in slide-in-from-bottom-4 duration-500 ${
                  aiAdvice.status === 'critical' ? 'bg-red-500/10 border-red-500' : 
                  aiAdvice.status === 'warning' ? 'bg-yellow-500/10 border-yellow-500' : 
                  'bg-emerald-500/10 border-emerald-500'
                }`}>
                  <p className="text-lg font-medium mb-4 italic">"{aiAdvice.message}"</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {aiAdvice.recommendations.map((rec, i) => (
                      <div key={i} className="flex items-start gap-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800">
                        <ChevronRightIcon className="w-5 h-5 text-emerald-400 flex-shrink-0 mt-0.5" />
                        <span className="text-sm text-slate-300">{rec}</span>
                      </div>
                    ))}
                  </div>
                </div>
              ) : (
                <div className="text-center py-12 border-2 border-dashed border-slate-800 rounded-2xl">
                  <p className="text-slate-500 text-sm">Adicione transações e clique em "Pedir Mentoria" para receber feedback estratégico.</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right Column: Entry & History */}
        <div className="lg:col-span-4 space-y-8">

          {/* Quick Add Form */}
          <div className="glass p-6 rounded-3xl sticky top-24">
            <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <PlusIcon className="w-5 h-5 text-emerald-400" />
              Novo Gasto
            </h3>
            <form onSubmit={handleAddTransaction} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold ml-1">Descrição</label>
                <input
                  type="text"
                  placeholder="Ex: Almoço no Polana"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold ml-1">Valor (MT)</label>
                <input
                  type="number"
                  placeholder="0.00"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold ml-1">Categoria (Regra 50/30/20)</label>
                <div className="grid grid-cols-3 gap-2">
                  <button
                    type="button"
                    onClick={() => setCategory(CategoryType.NEED)}
                    className={`text-[10px] py-2 rounded-lg border transition-all ${category === CategoryType.NEED ? 'bg-blue-500/20 border-blue-500 text-blue-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                  >
                    Necessidade
                  </button>
                  <button
                    type="button"
                    onClick={() => setCategory(CategoryType.WANT)}
                    className={`text-[10px] py-2 rounded-lg border transition-all ${category === CategoryType.WANT ? 'bg-purple-500/20 border-purple-500 text-purple-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                  >
                    Desejo
                  </button>
                  <button
                    type="button"
                    onClick={() => setCategory(CategoryType.SAVING)}
                    className={`text-[10px] py-2 rounded-lg border transition-all ${category === CategoryType.SAVING ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                  >
                    Reserva
                  </button>
                </div>
              </div>
              <button
                type="submit"
                className="w-full bg-slate-100 hover:bg-white text-slate-950 font-bold py-3 rounded-xl transition-all shadow-lg"
              >
                Catalogar Gasto
              </button>
            </form>
          </div>

          {/* History */}
          <div className="glass p-6 rounded-3xl min-h-[400px]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-semibold flex items-center gap-2">
                Histórico
              </h3>
              <span className="text-[10px] bg-slate-800 px-2 py-1 rounded text-slate-400">Recentes</span>
            </div>
            <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
              {transactions.length === 0 ? (
                <div className="text-center py-20">
                  <PieChartIcon className="w-12 h-12 text-slate-800 mx-auto mb-4" />
                  <p className="text-slate-600 text-sm">Nenhum gasto catalogado ainda.</p>
                </div>
              ) : (
                transactions.map((t) => (
                  <div key={t.id} className="group flex items-center justify-between p-3 rounded-2xl bg-slate-900/50 hover:bg-slate-900 transition-all border border-transparent hover:border-slate-800">
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-8 rounded-full ${
                        t.category === CategoryType.NEED ? 'bg-blue-500' : 
                        t.category === CategoryType.WANT ? 'bg-purple-500' : 
                        'bg-emerald-500'
                      }`} />
                      <div>
                        <p className="text-sm font-medium">{t.description}</p>
                        <p className="text-[10px] text-slate-500">{new Date(t.date).toLocaleDateString()}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="font-bold text-sm">{formatCurrency(t.amount)}</span>
                      <button 
                        onClick={() => removeTransaction(t.id)}
                        className="opacity-0 group-hover:opacity-100 p-2 text-slate-600 hover:text-red-400 transition-all"
                      >
                        <Trash2Icon className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>

        </div>
      </main>

      {/* Footer Branding */}
      <footer className="fixed bottom-0 left-0 right-0 bg-slate-950/80 backdrop-blur-md border-t border-slate-900 py-3 flex justify-center items-center text-[10px] tracking-[0.2em] text-slate-600 uppercase">
        © 2024 Finmo - Inteligência Financeira em Meticais
      </footer>
    </div>
  );
};

export default App;

