import React, { useState, useEffect, useMemo } from 'react';
import { 
  PlusIcon, 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon,
  TagIcon
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice } from './types';
import { CURRENCY, CATEGORY_LABELS, CATEGORY_COLORS, SUBCATEGORIES, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [income, setIncome] = useState<number>(30000);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [description, setDescription] = useState('');
