import { GoogleGenAI, Type } from "@google/genai";
import { Transaction, CategoryType, BudgetStats } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getFinancialAdvice = async (
  stats: BudgetStats,
  transactions: Transaction[],
  income: number
) => {
  const prompt = `
    Atue como Finmo, um mentor financeiro especializado na regra 50/30/20. 
    Analise os seguintes dados financeiros do usuário (Moeda: Metical - MT):

    Renda Mensal: ${income} MT
    Gastos em Necessidades (Meta 50%): ${stats.needs + stats.debtInterest + stats.debtNoInterest} MT (Incluindo dívidas)
    Dívidas com Juros: ${stats.debtInterest} MT (URGENTE)
    Dívidas sem Juros: ${stats.debtNoInterest} MT
    Gastos em Desejos (Meta 30%): ${stats.wants} MT
    Investimentos/Reserva (Meta 20%): ${stats.savings} MT

    Lista de transações recentes:
    ${transactions.slice(0, 15).map(t => `- ${t.description}: ${t.amount} MT (${t.category})`).join('\n')}

    Sua resposta deve ser em JSON seguindo este esquema:
    {
      "status": "good" | "warning" | "critical",
      "message": "Uma mensagem curta, pragmática e incentivadora.",
      "recommendations": ["Recomendação 1", "Recomendação 2", "Recomendação 3"]
    }

    Regras de Mentoria:
    1. Dívida com Juros (DEBT_INTEREST) é o "incêndio". Se houver esse tipo de gasto, o status deve ser pelo menos 'warning' ou 'critical'. 
    2. Recomende quitar dívidas com juros ANTES de focar agressivamente em investimentos.
    3. Se o somatório de (Necessidades + Dívidas) passar de 50%, aponte o risco.
    4. Se Desejos (Wants) passar de 30%, sugira cortes específicos.
    5. Fale em Meticais (MT).
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            message: { type: Type.STRING },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["status", "message", "recommendations"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Erro ao obter conselho da IA:", error);
    return {
      status: 'warning',
      message: 'Não consegui analisar seus dados agora, mas vi dívidas registradas. Priorize pagar aquelas com juros altos!',
      recommendations: ['Estanque os juros do cartão', 'Negocie prazos', 'Mantenha o foco']
    };
  }
};

