  [CategoryType.WANT]: '#a855f7', // purple-500
  [CategoryType.SAVING]: '#10b981', // emerald-500
  [CategoryType.DEBT_INTEREST]: '#ef4444', // red-500
  [CategoryType.DEBT_NO_INTEREST]: '#f97316' // orange-500
