export const formatCurrency = (amount: number): string => {
  return new Intl.NumberFormat('pt-MZ', {
    style: 'currency',
    currency: 'MZN',
  }).format(amount).replace('MZN', CURRENCY);
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PlusIcon, 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon,
  TagIcon,
  AlertTriangleIcon,
  XIcon,
  RotateCcwIcon,
  CalendarIcon,
  ArrowRightIcon,
  FlameIcon,
  HandCoinsIcon
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice } from './types';
import { CURRENCY, CATEGORY_LABELS, CATEGORY_COLORS, SUBCATEGORIES, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  // Initialize state from localStorage or defaults
  const [income, setIncome] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_income');
    return saved ? Number(saved) : 30000;
  });

  const [payday, setPayday] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_payday');
    return saved ? Number(saved) : 1;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finmo_transactions');
    try {
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Erro ao carregar transações:", e);
      return [];
    }
  });

  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState<CategoryType>(CategoryType.NEED);
  const [subcategory, setSubcategory] = useState<string>(SUBCATEGORIES[CategoryType.NEED][0]);
  const [aiAdvice, setAiAdvice] = useState<AIAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);

  // Delete confirmation state
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [transactionToDelete, setTransactionToDelete] = useState<string | null>(null);

  // Reset confirmation state
  const [showResetModal, setShowResetModal] = useState(false);

  // Persistence effects
  useEffect(() => {
    localStorage.setItem('finmo_income', income.toString());
  }, [income]);

  useEffect(() => {
    localStorage.setItem('finmo_payday', payday.toString());
  }, [payday]);

  useEffect(() => {
    localStorage.setItem('finmo_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // Update subcategory when main category changes
  useEffect(() => {
    setSubcategory(SUBCATEGORIES[category][0]);
  }, [category]);

  // Statistics calculation
  const stats = useMemo<BudgetStats>(() => {
    const initialStats = { needs: 0, wants: 0, savings: 0, debtInterest: 0, debtNoInterest: 0, totalSpent: 0, income };
    return transactions.reduce((acc, t) => {
      if (t.category === CategoryType.NEED) acc.needs += t.amount;
      if (t.category === CategoryType.WANT) acc.wants += t.amount;
      if (t.category === CategoryType.SAVING) acc.savings += t.amount;
      if (t.category === CategoryType.DEBT_INTEREST) acc.debtInterest += t.amount;
      if (t.category === CategoryType.DEBT_NO_INTEREST) acc.debtNoInterest += t.amount;
      acc.totalSpent += t.amount;
      return acc;
    }, initialStats);
  }, [transactions, income]);

  // Targets for 50/30/20 Rule
  // Note: Debts are grouped into "Needs" for the macro target calculation
  const targets = {
    [CategoryType.NEED]: income * 0.5,
    [CategoryType.WANT]: income * 0.3,
    [CategoryType.SAVING]: income * 0.2,
    [CategoryType.DEBT_INTEREST]: 0, // Ideally 0
    [CategoryType.DEBT_NO_INTEREST]: 0 // Ideally 0
  };

  const chartData = [
    { name: 'Essenciais*', real: stats.needs + stats.debtInterest + stats.debtNoInterest, target: targets[CategoryType.NEED], color: CATEGORY_COLORS[CategoryType.NEED] },
    { name: 'Desejos', real: stats.wants, target: targets[CategoryType.WANT], color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', real: stats.savings, target: targets[CategoryType.SAVING], color: CATEGORY_COLORS[CategoryType.SAVING] },
  ];

  const pieData = [
    { name: 'Necessidades', value: stats.needs, color: CATEGORY_COLORS[CategoryType.NEED] },
    { name: 'Desejos', value: stats.wants, color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', value: stats.savings, color: CATEGORY_COLORS[CategoryType.SAVING] },
    { name: 'Dívida', value: stats.debtInterest, color: CATEGORY_COLORS[CategoryType.DEBT_INTEREST] },
    { name: 'Dívida s/ Juros', value: stats.debtNoInterest, color: CATEGORY_COLORS[CategoryType.DEBT_NO_INTEREST] },
    { name: 'Disponível', value: Math.max(0, income - stats.totalSpent), color: '#334155' },
  ];

  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    const newTransaction: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description,
      amount: parseFloat(amount),
      category,
      subcategory,
      date: new Date().toISOString(),
    };

    setTransactions([newTransaction, ...transactions]);
    setDescription('');
    setAmount('');
  };

  const confirmRemoveTransaction = (id: string) => {
    setTransactionToDelete(id);
    setShowDeleteModal(true);
  };

  const executeDelete = () => {
    if (transactionToDelete) {
      setTransactions(transactions.filter(t => t.id !== transactionToDelete));
      setTransactionToDelete(null);
      setShowDeleteModal(false);
    }
  };

  const handleResetData = () => {
    setTransactions([]);
    setIncome(30000);
    setPayday(1);
    setAiAdvice(null);
    localStorage.removeItem('finmo_income');
    localStorage.removeItem('finmo_payday');
    localStorage.removeItem('finmo_transactions');
    setShowResetModal(false);
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, income);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  // Helper to check if a transaction is "problematic" and why
  const getProblematicReason = (t: Transaction) => {
    // Critical alert for any debt with interest
    if (t.category === CategoryType.DEBT_INTEREST) return 'Dívida corrói seu patrimônio';

    const macroNeedsSpent = stats.needs + stats.debtInterest + stats.debtNoInterest;
    const isNeedsOver = t.category === CategoryType.NEED && macroNeedsSpent > targets[CategoryType.NEED];
    const isWantsOver = t.category === CategoryType.WANT && stats.wants > targets[CategoryType.WANT];

    const isLarge = t.amount > (income * 0.05); // More than 5% of income

    if (isWantsOver) return 'Contribui para estouro de Desejos';
    if (isNeedsOver) return 'Necessidades + Dívidas excedem 50%';
    if (isLarge) return 'Gasto individual elevado (>5% renda)';

    return null;
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      {/* Header */}
      <header className="sticky top-0 z-50 glass border-b border-slate-800 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-500 p-2 rounded-xl shadow-lg shadow-emerald-500/20">
            <WalletIcon className="w-6 h-6 text-slate-900" />
          </div>
          <h1 className="text-2xl font-bold tracking-tight">Finmo</h1>
        </div>

        <div className="flex items-center gap-4 sm:gap-8">
          <div className="flex items-center gap-4 sm:gap-6">
            <div className="text-right hidden md:block">
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Renda Mensal</p>
              <div className="flex items-center justify-end gap-1">
                <span className="text-xs text-emerald-500/60 font-medium">MT</span>
                <input 
                  type="number" 
                  value={income} 
                  onChange={(e) => setIncome(Number(e.target.value))}
                  className="bg-transparent text-right font-bold text-emerald-400 focus:outline-none w-24 border-b border-transparent focus:border-emerald-500 transition-colors"
                />
              </div>
            </div>

            <div className="text-right hidden sm:block">
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Dia do Salário</p>
              <div className="flex items-center justify-end gap-2">
                <CalendarIcon className="w-3 h-3 text-slate-500" />
                <input 
                  type="number" 
                  min="1" 
                  max="31"
                  value={payday} 
                  onChange={(e) => setPayday(Number(e.target.value))}
                  className="bg-transparent text-right font-bold text-slate-200 focus:outline-none w-10 border-b border-transparent focus:border-emerald-500 transition-colors"
                />
              </div>
            </div>
          </div>

          <button 
            onClick={() => setShowResetModal(true)}
            className="p-2 text-slate-500 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-all"
            title="Limpar todos os dados"
          >
            <RotateCcwIcon className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Dashboard Stats */}
        <div className="lg:col-span-8 space-y-8">

          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {[
              { type: CategoryType.NEED, label: 'Essenciais*', val: stats.needs + stats.debtInterest + stats.debtNoInterest, target: targets[CategoryType.NEED], color: 'blue', icon: CreditCardIcon },
              { type: CategoryType.WANT, label: 'Desejos', val: stats.wants, target: targets[CategoryType.WANT], color: 'purple', icon: PieChartIcon },
              { type: CategoryType.SAVING, label: 'Reserva', val: stats.savings, target: targets[CategoryType.SAVING], color: 'emerald', icon: TrendingUpIcon }
            ].map((card) => {
              const isOver = card.val > card.target;
              return (
                <div 
                  key={card.type}
                  className={`glass p-6 rounded-3xl space-y-2 border-l-4 transition-all duration-500 ${
                    isOver ? 'border-red-500 shadow-[0_0_20px_rgba(239,68,68,0.2)]' : `border-${card.color}-500`
                  }`}
                >
                  <div className="flex justify-between items-start">
                    <p className="text-slate-400 text-sm flex items-center gap-1">
                      {card.label}
                      {isOver && <AlertTriangleIcon className="w-3 h-3 text-red-500 animate-pulse" />}
                    </p>
                    <div className={isOver ? 'bg-red-500/10 p-2 rounded-lg' : `bg-${card.color}-500/10 p-2 rounded-lg`}>
                      <card.icon className={`w-4 h-4 ${isOver ? 'text-red-500' : `text-${card.color}-500`}`} />
                    </div>
                  </div>
                  <p className={`text-xl font-bold ${isOver ? 'text-red-400' : ''}`}>{formatCurrency(card.val)}</p>
                  <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
                    <div 
                      className={`${isOver ? 'bg-red-500' : `bg-${card.color}-500`} h-full transition-all duration-500`} 
                      style={{ width: `${Math.min(100, (card.val / (card.target || 1)) * 100)}%` }}
                    />
                  </div>
                  <div className="flex justify-between items-center">
                    <p className="text-[10px] text-slate-500">Meta: {formatCurrency(card.target)}</p>
                    {isOver && (
                      <span className="text-[10px] font-bold text-red-500 uppercase tracking-tighter">Estourou!</span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          {/* Debt Summary Row - If exists */}
          {(stats.debtInterest > 0 || stats.debtNoInterest > 0) && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 animate-in fade-in slide-in-from-top-4 duration-500">
              <div className="glass p-4 rounded-2xl flex items-center justify-between border-l-4 border-red-500 bg-red-500/5">
                <div className="flex items-center gap-3">
                  <div className="bg-red-500/20 p-2 rounded-xl">
                    <FlameIcon className="w-5 h-5 text-red-500" />
                  </div>
                  <div>
                    <p className="text-[10px] text-red-400 font-bold uppercase tracking-wider">Dívida Ativa</p>
                    <p className="text-lg font-black text-red-100">{formatCurrency(stats.debtInterest)}</p>
                  </div>
                </div>
                <div className="text-right">
                  <span className="text-[10px] text-red-500 font-bold block">ALERTA</span>
                  <span className="text-[8px] text-red-400/60 uppercase">Risco Elevado</span>
                </div>
              </div>
              <div className="glass p-4 rounded-2xl flex items-center justify-between border-l-4 border-orange-500 bg-orange-500/5">
                <div className="flex items-center gap-3">
                  <div className="bg-orange-500/20 p-2 rounded-xl">
                    <HandCoinsIcon className="w-5 h-5 text-orange-500" />
                  </div>
                  <div>
                    <p className="text-[10px] text-orange-400 font-bold uppercase tracking-wider">Dívida s/ Juros</p>
                    <p className="text-lg font-black text-orange-100">{formatCurrency(stats.debtNoInterest)}</p>
                  </div>
                </div>
                <div className="text-right text-[8px] text-orange-400/60 uppercase">
                  Compromisso Mensal
                </div>
              </div>
            </div>
          )}

          {/* Charts Section */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="glass p-6 rounded-3xl">
              <h3 className="text-lg font-semibold mb-6 flex items-center gap-2">
                <TrendingUpIcon className="w-5 h-5 text-emerald-400" />
                Real vs Meta (50/30/20)
              </h3>
              <div className="h-64 w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
                    <XAxis dataKey="name" stroke="#64748b" fontSize={12} tickLine={false} axisLine={false} />
                    <YAxis stroke="#64748b" fontSize={10} tickLine={false} axisLine={false} />
                    <Tooltip 
                      contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px' }}
                      itemStyle={{ fontSize: '12px' }}
                    />
                    <Bar dataKey="real" radius={[4, 4, 0, 0]} barSize={32}>
                      {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.real > entry.target ? '#ef4444' : entry.color} />
                      ))}
                    </Bar>
                    <Bar dataKey="target" fill="#334155" radius={[4, 4, 0, 0]} barSize={10} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="glass p-6 rounded-3xl">
              <h3 className="text-lg font-semibold mb-6 flex items-center gap-2">
                <PieChartIcon className="w-5 h-5 text-emerald-400" />
                Alocação Detalhada
              </h3>
              <div className="h-64 w-full relative">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={pieData.filter(d => d.value > 0)}
                      cx="50%"
                      cy="50%"
                      innerRadius={60}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="value"
                    >
                      {pieData.filter(d => d.value > 0).map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <span className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Saldo</span>
                  <span className="text-lg font-bold">{formatCurrency(Math.max(0, income - stats.totalSpent))}</span>
                </div>
              </div>
            </div>
          </div>

          {/* AI Mentorship Section */}
          <div className="relative overflow-hidden group">
            <div className="absolute -inset-1 bg-gradient-to-r from-emerald-500 to-blue-500 rounded-3xl blur opacity-25 group-hover:opacity-40 transition duration-1000"></div>
            <div className="relative glass p-8 rounded-3xl space-y-6">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <div className="bg-emerald-500/20 p-3 rounded-2xl">
                    <SparklesIcon className="w-6 h-6 text-emerald-400" />
                  </div>
                  <div>
                    <h2 className="text-xl font-bold">Conselheiro Finmo</h2>
                    <p className="text-sm text-slate-400">Análise inteligente e pragmática</p>
                  </div>
                </div>
                <button 
                  onClick={getMentorship}
                  disabled={loadingAdvice || transactions.length === 0}
                  className="bg-emerald-500 hover:bg-emerald-600 disabled:opacity-50 text-slate-950 font-bold py-2 px-6 rounded-xl transition-all flex items-center gap-2"
                >
                  {loadingAdvice ? "Analisando..." : "Pedir Mentoria"}
                </button>
              </div>

              {aiAdvice ? (
                <div className={`p-6 rounded-2xl border-l-4 animate-in fade-in slide-in-from-bottom-4 duration-500 ${
                  aiAdvice.status === 'critical' ? 'bg-red-500/10 border-red-500' : 
                  aiAdvice.status === 'warning' ? 'bg-yellow-500/10 border-yellow-500' : 
                  'bg-emerald-500/10 border-emerald-500'
                }`}>
                  <p className="text-lg font-medium mb-4 italic">"{aiAdvice.message}"</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {aiAdvice.recommendations.map((rec, i) => (
                      <div key={i} className="flex items-start gap-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800">
                        <ChevronRightIcon className="w-5 h-5 text-emerald-400 flex-shrink-0 mt-0.5" />
                        <span className="text-sm text-slate-300">{rec}</span>
                      </div>
                    ))}
                  </div>
                </div>
              ) : (
                <div className="text-center py-12 border-2 border-dashed border-slate-800 rounded-2xl">
                  <p className="text-slate-500 text-sm">Adicione transações e clique em "Pedir Mentoria" para receber feedback estratégico.</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right Column: Entry & History */}
        <div className="lg:col-span-4 space-y-8">

          {/* Quick Add Form */}
          <div className="glass p-6 rounded-3xl sticky top-24">
            <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <PlusIcon className="w-5 h-5 text-emerald-400" />
              Novo Gasto
            </h3>
            <form onSubmit={handleAddTransaction} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold ml-1">Descrição</label>
                <input
                  type="text"
                  placeholder="Ex: Almoço no Polana"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold ml-1">Valor (MT)</label>
                <input
                  type="number"
                  placeholder="0.00"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold ml-1">Categoria Principal</label>
                <div className="grid grid-cols-2 gap-2">
                  <button
                    type="button"
                    onClick={() => setCategory(CategoryType.NEED)}
                    className={`text-[10px] py-2 rounded-lg border transition-all ${category === CategoryType.NEED ? 'bg-blue-500/20 border-blue-500 text-blue-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                  >
                    Necessidade
                  </button>
                  <button
                    type="button"
                    onClick={() => setCategory(CategoryType.WANT)}
                    className={`text-[10px] py-2 rounded-lg border transition-all ${category === CategoryType.WANT ? 'bg-purple-500/20 border-purple-500 text-purple-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                  >
                    Desejo
                  </button>
                  <button
                    type="button"
                    onClick={() => setCategory(CategoryType.SAVING)}
                    className={`text-[10px] py-2 rounded-lg border transition-all ${category === CategoryType.SAVING ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                  >
                    Reserva
                  </button>
                  <button
                    type="button"
                    onClick={() => setCategory(CategoryType.DEBT_INTEREST)}
                    className={`text-[10px] py-2 rounded-lg border transition-all ${category === CategoryType.DEBT_INTEREST ? 'bg-red-500/20 border-red-500 text-red-400 font-bold' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                  >
                    Dívida
                  </button>
                  <button
                    type="button"
                    onClick={() => setCategory(CategoryType.DEBT_NO_INTEREST)}
                    className={`text-[10px] py-2 rounded-lg border transition-all col-span-2 ${category === CategoryType.DEBT_NO_INTEREST ? 'bg-orange-500/20 border-orange-500 text-orange-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                  >
                    Dívida s/ Juros
                  </button>
                </div>
              </div>

              {/* Dynamic Subcategory Selection */}
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-bold ml-1 flex items-center gap-1">
                  <TagIcon className="w-3 h-3" /> Subcategoria
                </label>
                <select
                  value={subcategory}
                  onChange={(e) => setSubcategory(e.target.value)}
                  className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none transition-all text-sm appearance-none"
                >
                  {SUBCATEGORIES[category].map((sub) => (
                    <option key={sub} value={sub}>{sub}</option>
                  ))}
                </select>
              </div>

              <button
                type="submit"
                className="w-full bg-slate-100 hover:bg-white text-slate-950 font-bold py-3 rounded-xl transition-all shadow-lg"
              >
                Catalogar Gasto
              </button>
            </form>
          </div>

          {/* History */}
          <div className="glass p-6 rounded-3xl min-h-[400px]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-semibold flex items-center gap-2">
                Histórico
              </h3>
              <span className="text-[10px] bg-slate-800 px-2 py-1 rounded text-slate-400 font-bold uppercase tracking-widest">Recentes</span>
            </div>
            <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
              {transactions.length === 0 ? (
                <div className="text-center py-20">
                  <PieChartIcon className="w-12 h-12 text-slate-800 mx-auto mb-4" />
                  <p className="text-slate-600 text-sm">Nenhum gasto catalogado ainda.</p>
                </div>
              ) : (
                transactions.map((t) => {
                  const alertReason = getProblematicReason(t);
                  const isDebt = t.category === CategoryType.DEBT_INTEREST || t.category === CategoryType.DEBT_NO_INTEREST;

                  return (
                    <div 
                      key={t.id} 
                      className={`group relative overflow-hidden flex flex-col p-4 rounded-2xl transition-all border ${
                        alertReason 
                          ? 'bg-red-500/10 border-red-500/40 shadow-lg shadow-red-950/20' 
                          : 'bg-slate-900/50 border-transparent hover:bg-slate-900 hover:border-slate-800'
                      }`}
                    >
                      {/* Highlight bar */}
                      <div className={`absolute left-0 top-0 bottom-0 w-1.5 ${
                        CATEGORY_COLORS[t.category]
                      }`} style={{ backgroundColor: CATEGORY_COLORS[t.category] }} />

                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div>
                            <p className="text-sm font-bold flex items-center gap-2">
                              {t.description}
                              {alertReason && (
                                <AlertTriangleIcon className="w-4 h-4 text-red-500 animate-pulse" />
                              )}
                            </p>
                            <div className="flex items-center gap-2 mt-0.5">
                              <p className="text-[10px] text-slate-500">{new Date(t.date).toLocaleDateString()}</p>
                              <span className="w-1 h-1 rounded-full bg-slate-800" />
                              <span className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{t.subcategory}</span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-4">
                          <div className="text-right">
                            <span className={`font-black text-base block ${alertReason ? 'text-red-400' : 'text-slate-100'}`}>
                              {formatCurrency(t.amount)}
                            </span>
                          </div>
                          <button 
                            onClick={() => confirmRemoveTransaction(t.id)}
                            className="opacity-0 group-hover:opacity-100 p-2 text-slate-600 hover:text-red-400 transition-all rounded-lg hover:bg-slate-800"
                            title="Remover transação"
                          >
                            <Trash2Icon className="w-4 h-4" />
                          </button>
                        </div>
                      </div>

                      {/* Alert details */}
                      {alertReason && (
                        <div className="mt-3 pt-3 border-t border-red-500/20 flex items-start gap-2 animate-in fade-in slide-in-from-top-1 duration-300">
                          <div className="bg-red-500/20 p-1 rounded">
                            <AlertTriangleIcon className="w-3 h-3 text-red-500" />
                          </div>
                          <div className="flex-1">
                            <p className="text-[10px] font-black text-red-400 uppercase tracking-tight">
                              ATENÇÃO: {alertReason}
                            </p>
                            <p className="text-[9px] text-red-300/60 leading-tight">
                              {isDebt ? 'Dívidas impedem sua liberdade financeira.' : `Este gasto compromete sua meta de saúde financeira.`}
                            </p>
                          </div>
                          <div className={`flex items-center text-[9px] font-bold px-1.5 py-0.5 rounded border ${
                            t.category === CategoryType.DEBT_INTEREST ? 'text-red-400 bg-red-500/10 border-red-500/20' : 'text-orange-400 bg-orange-500/10 border-orange-500/20'
                          }`}>
                            {t.category === CategoryType.DEBT_INTEREST ? 'CRÍTICO' : 'ALERTA'}
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })
              )}
            </div>
          </div>

        </div>
      </main>

      {/* Confirmation Modal - Delete */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div 
            className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" 
            onClick={() => setShowDeleteModal(false)}
          />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6 shadow-2xl border-slate-700 animate-in fade-in zoom-in duration-200">
            <div className="flex justify-center">
              <div className="bg-red-500/20 p-4 rounded-full">
                <AlertTriangleIcon className="w-8 h-8 text-red-500" />
              </div>
            </div>
            <div className="text-center space-y-2">
              <h3 className="text-xl font-bold">Apagar Transação?</h3>
              <p className="text-slate-400 text-sm">
                Esta ação não pode ser desfeita. Tem certeza que deseja remover este gasto do seu histórico?
              </p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => setShowDeleteModal(false)}
                className="py-3 px-4 rounded-xl bg-slate-800 hover:bg-slate-700 text-slate-300 font-semibold transition-all"
              >
                Cancelar
              </button>
              <button 
                onClick={executeDelete}
                className="py-3 px-4 rounded-xl bg-red-600 hover:bg-red-500 text-white font-semibold transition-all shadow-lg shadow-red-900/20"
              >
                Sim, Apagar
              </button>
            </div>
            <button 
              onClick={() => setShowDeleteModal(false)}
              className="absolute top-4 right-4 p-2 text-slate-500 hover:text-white transition-all"
            >
              <XIcon className="w-5 h-5" />
            </button>
          </div>
        </div>
      )}

      {/* Confirmation Modal - Reset */}
      {showResetModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div 
            className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" 
            onClick={() => setShowResetModal(false)}
          />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6 shadow-2xl border-slate-700 animate-in fade-in zoom-in duration-200">
            <div className="flex justify-center">
              <div className="bg-yellow-500/20 p-4 rounded-full">
                <RotateCcwIcon className="w-8 h-8 text-yellow-500" />
              </div>
            </div>
            <div className="text-center space-y-2">
              <h3 className="text-xl font-bold">Reiniciar Tudo?</h3>
              <p className="text-slate-400 text-sm">
                Isso apagará todas as suas transações e voltará a renda mensal ao valor padrão. Deseja continuar?
              </p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => setShowResetModal(false)}
                className="py-3 px-4 rounded-xl bg-slate-800 hover:bg-slate-700 text-slate-300 font-semibold transition-all"
              >
                Cancelar
              </button>
              <button 
                onClick={handleResetData}
                className="py-3 px-4 rounded-xl bg-yellow-600 hover:bg-yellow-500 text-white font-semibold transition-all shadow-lg shadow-yellow-900/20"
              >
                Reiniciar
              </button>
            </div>
            <button 
              onClick={() => setShowResetModal(false)}
              className="absolute top-4 right-4 p-2 text-slate-500 hover:text-white transition-all"
            >
              <XIcon className="w-5 h-5" />
            </button>
          </div>
        </div>
      )}

      {/* Footer Branding */}
      <footer className="fixed bottom-0 left-0 right-0 bg-slate-950/80 backdrop-blur-md border-t border-slate-900 py-3 flex justify-center items-center text-[10px] tracking-[0.2em] text-slate-600 uppercase">
        © 2024 Finmo - Inteligência Financeira em Meticais
      </footer>
    </div>
  );
};

export default App;

export enum CategoryType {
  NEED = 'NEED',      // 50%
  WANT = 'WANT',      // 30%
  SAVING = 'SAVING',  // 20%
  DEBT_INTEREST = 'DEBT_INTEREST',
  DEBT_NO_INTEREST = 'DEBT_NO_INTEREST'
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  category: CategoryType;
  subcategory: string;
  date: string;
  dueDate?: string; // Optional due date for debts
}

export interface BudgetStats {
  income: number;
  needs: number;
  wants: number;
  savings: number;
  debtInterest: number;
  debtNoInterest: number;
  totalSpent: number;
}

export interface AIAdvice {
  status: 'good' | 'warning' | 'critical';
  message: string;
  recommendations: string[];
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PlusIcon, 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon,
  TagIcon,
  AlertTriangleIcon,
  XIcon,
  RotateCcwIcon,
  CalendarIcon,
  ArrowRightIcon,
  FlameIcon,
  HandCoinsIcon,
  ClockIcon
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice } from './types';
import { CURRENCY, CATEGORY_LABELS, CATEGORY_COLORS, SUBCATEGORIES, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  // Initialize state from localStorage or defaults
  const [income, setIncome] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_income');
    return saved ? Number(saved) : 30000;
  });

  const [payday, setPayday] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_payday');
    return saved ? Number(saved) : 1;
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finmo_transactions');
    try {
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Erro ao carregar transações:", e);
      return [];
    }
  });

  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState<CategoryType>(CategoryType.NEED);
  const [subcategory, setSubcategory] = useState<string>(SUBCATEGORIES[CategoryType.NEED][0]);
  const [dueDate, setDueDate] = useState('');
  const [aiAdvice, setAiAdvice] = useState<AIAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);

  // Delete confirmation state
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [transactionToDelete, setTransactionToDelete] = useState<string | null>(null);

  // Reset confirmation state
  const [showResetModal, setShowResetModal] = useState(false);

  // Persistence effects
  useEffect(() => {
    localStorage.setItem('finmo_income', income.toString());
  }, [income]);

  useEffect(() => {
    localStorage.setItem('finmo_payday', payday.toString());
  }, [payday]);

  useEffect(() => {
    localStorage.setItem('finmo_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // Update subcategory when main category changes
  useEffect(() => {
    setSubcategory(SUBCATEGORIES[category][0]);
    // Reset due date if not a debt category
    if (category !== CategoryType.DEBT_INTEREST && category !== CategoryType.DEBT_NO_INTEREST) {
      setDueDate('');
    }
  }, [category]);

  // Statistics calculation
  const stats = useMemo<BudgetStats>(() => {
    const initialStats = { needs: 0, wants: 0, savings: 0, debtInterest: 0, debtNoInterest: 0, totalSpent: 0, income };
    return transactions.reduce((acc, t) => {
      if (t.category === CategoryType.NEED) acc.needs += t.amount;
      if (t.category === CategoryType.WANT) acc.wants += t.amount;
      if (t.category === CategoryType.SAVING) acc.savings += t.amount;
      if (t.category === CategoryType.DEBT_INTEREST) acc.debtInterest += t.amount;
      if (t.category === CategoryType.DEBT_NO_INTEREST) acc.debtNoInterest += t.amount;
      acc.totalSpent += t.amount;
      return acc;
    }, initialStats);
  }, [transactions, income]);

  // Targets for 50/30/20 Rule
  const targets = {
    [CategoryType.NEED]: income * 0.5,
    [CategoryType.WANT]: income * 0.3,
    [CategoryType.SAVING]: income * 0.2,
    [CategoryType.DEBT_INTEREST]: 0, 
    [CategoryType.DEBT_NO_INTEREST]: 0 
  };

  const chartData = [
    { name: 'Essenciais*', real: stats.needs + stats.debtInterest + stats.debtNoInterest, target: targets[CategoryType.NEED], color: CATEGORY_COLORS[CategoryType.NEED] },
    { name: 'Desejos', real: stats.wants, target: targets[CategoryType.WANT], color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', real: stats.savings, target: targets[CategoryType.SAVING], color: CATEGORY_COLORS[CategoryType.SAVING] },
  ];

  const pieData = [
    { name: 'Necessidades', value: stats.needs, color: CATEGORY_COLORS[CategoryType.NEED] },
    { name: 'Desejos', value: stats.wants, color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', value: stats.savings, color: CATEGORY_COLORS[CategoryType.SAVING] },
    { name: 'Dívida', value: stats.debtInterest, color: CATEGORY_COLORS[CategoryType.DEBT_INTEREST] },
    { name: 'Dívida s/ Juros', value: stats.debtNoInterest, color: CATEGORY_COLORS[CategoryType.DEBT_NO_INTEREST] },
    { name: 'Disponível', value: Math.max(0, income - stats.totalSpent), color: '#334155' },
  ];

  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    const newTransaction: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      description,
      amount: parseFloat(amount),
      category,
      subcategory,
      date: new Date().toISOString(),
      dueDate: (category === CategoryType.DEBT_INTEREST || category === CategoryType.DEBT_NO_INTEREST) ? dueDate : undefined
    };

    setTransactions([newTransaction, ...transactions]);
    setDescription('');
    setAmount('');
    setDueDate('');
  };

  const confirmRemoveTransaction = (id: string) => {
    setTransactionToDelete(id);
    setShowDeleteModal(true);
  };

  const executeDelete = () => {
    if (transactionToDelete) {
      setTransactions(transactions.filter(t => t.id !== transactionToDelete));
      setTransactionToDelete(null);
      setShowDeleteModal(false);
    }
  };

  const handleResetData = () => {
    setTransactions([]);
    setIncome(30000);
    setPayday(1);
    setAiAdvice(null);
    localStorage.removeItem('finmo_income');
    localStorage.removeItem('finmo_payday');
    localStorage.removeItem('finmo_transactions');
    setShowResetModal(false);
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, income);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  const getProblematicReason = (t: Transaction) => {
    // Near due date alert
    if (t.dueDate) {
      const today = new Date();
      const due = new Date(t.dueDate);
      const diffTime = due.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays >= 0 && diffDays <= 3) return `Vencimento próximo (${diffDays} dias)`;
      if (diffDays < 0) return `Vencimento atrasado há ${Math.abs(diffDays)} dias`;
    }

    // Critical alert for any debt with interest
    if (t.category === CategoryType.DEBT_INTEREST) return 'Dívida corrói seu patrimônio';

    const macroNeedsSpent = stats.needs + stats.debtInterest + stats.debtNoInterest;
    const isNeedsOver = t.category === CategoryType.NEED && macroNeedsSpent > targets[CategoryType.NEED];
    const isWantsOver = t.category === CategoryType.WANT && stats.wants > targets[CategoryType.WANT];

    const isLarge = t.amount > (income * 0.05); // More than 5% of income

    if (isWantsOver) return 'Contribui para estouro de Desejos';
    if (isNeedsOver) return 'Necessidades + Dívidas excedem 50%';
    if (isLarge) return 'Gasto individual elevado (>5% renda)';

    return null;
  };

  const isDebt = (cat: CategoryType) => cat === CategoryType.DEBT_INTEREST || cat === CategoryType.DEBT_NO_INTEREST;

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      {/* Header */}
      <header className="sticky top-0 z-50 glass border-b border-slate-800 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-500 p-2 rounded-xl shadow-lg shadow-emerald-500/20">
            <WalletIcon className="w-6 h-6 text-slate-900" />
          </div>
          <h1 className="text-2xl font-bold tracking-tight">Finmo</h1>
        </div>

        <div className="flex items-center gap-4 sm:gap-8">
