      id: Math.random().toString(36).substr(2, 9),
      description,
      amount: parseFloat(amount),
      category,
      subcategory,
      date: new Date().toISOString(),
      dueDate: (category === CategoryType.DEBT_INTEREST || category === CategoryType.DEBT_NO_INTEREST) ? dueDate : undefined
    };

