    setTransactionToDelete(id);
    setShowDeleteModal(true);
  };

  const executeDelete = () => {
    if (transactionToDelete) {
      setTransactions(transactions.filter(t => t.id !== transactionToDelete));
      setTransactionToDelete(null);
      setShowDeleteModal(false);
    }
  };

  const handleResetData = () => {
    setTransactions([]);
    setBaseIncome(30000);
    setPayday(1);
    setAiAdvice(null);
    localStorage.removeItem('finmo_income');
    localStorage.removeItem('finmo_payday');
    localStorage.removeItem('finmo_transactions');
    setShowResetModal(false);
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, stats.totalIncome);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  const getProblematicReason = (t: Transaction) => {
    if (t.category === CategoryType.INCOME) return null;

    if (t.dueDate) {
      const today = new Date();
      const due = new Date(t.dueDate);
      const diffTime = due.getTime() - today.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (diffDays >= 0 && diffDays <= 3) return `Vencimento próximo (${diffDays} dias)`;
      if (diffDays < 0) return `Vencimento atrasado há ${Math.abs(diffDays)} dias`;
    }

    if (t.category === CategoryType.DEBT_INTEREST) return 'Dívida corrói seu patrimônio';

    const macroNeedsSpent = stats.needs + stats.debtInterest + stats.debtNoInterest;
    const isNeedsOver = t.category === CategoryType.NEED && macroNeedsSpent > targets[CategoryType.NEED];
    const isWantsOver = t.category === CategoryType.WANT && stats.wants > targets[CategoryType.WANT];

    if (isWantsOver) return 'Contribui para estouro de Desejos';
    if (isNeedsOver) return 'Necessidades + Dívidas excedem 50%';

    return null;
  };

  const isDebt = (cat: CategoryType) => cat === CategoryType.DEBT_INTEREST || cat === CategoryType.DEBT_NO_INTEREST;

  return (
