        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        <div className="lg:col-span-8 space-y-8">

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {[
              { label: 'Essenciais*', val: stats.needs + stats.debtInterest + stats.debtNoInterest, target: targets[CategoryType.NEED], color: 'blue', icon: CreditCardIcon },
              { label: 'Desejos', val: stats.wants, target: targets[CategoryType.WANT], color: 'purple', icon: PieChartIcon },
              { label: 'Reserva', val: stats.savings, target: targets[CategoryType.SAVING], color: 'emerald', icon: TrendingUpIcon }
