            <div className="space-y-4">
              {transactions.length === 0 ? (
                <p className="text-center py-20 text-slate-600 text-sm italic">Nenhum gasto variável hoje.</p>
              ) : (
                transactions.map((t) => {
                  const alertReason = getProblematicReason(t);
                  const isInc = t.category === CategoryType.INCOME;
                  return (
                    <div key={t.id} className={`group relative p-4 rounded-2xl border transition-all ${isInc ? 'bg-emerald-500/5 border-emerald-500/20' : alertReason ? 'bg-red-500/10 border-red-500/30' : 'bg-slate-900/50 border-transparent hover:border-slate-800'}`}>
                      <div className={`absolute left-0 top-0 bottom-0 w-1 ${isInc ? 'bg-emerald-500' : CATEGORY_COLORS[t.category]}`} />
                      <div className="flex justify-between items-start">
                        <div>
                          <p className="text-sm font-bold">{t.description}</p>
                          <p className="text-[10px] text-slate-500 mt-1">{new Date(t.date).toLocaleDateString()} • {t.subcategory}</p>
                        </div>
                        <div className="flex items-center gap-3">
                           <span className={`font-black text-sm ${isInc ? 'text-emerald-400' : 'text-slate-100'}`}>{isInc ? '+' : '-'}{formatCurrency(t.amount)}</span>
                           <button onClick={() => { setTransactionToDelete(t.id); setShowDeleteModal(true); }} className="opacity-0 group-hover:opacity-100 p-1.5 text-slate-600 hover:text-red-400 transition-all"><Trash2Icon className="w-4 h-4" /></button>
                        </div>
                      </div>
                      {alertReason && <p className="text-[9px] font-black text-red-400 uppercase mt-2">ALERTA: {alertReason}</p>}
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>
      </main>

      {showDeleteModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowDeleteModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6">
            <h3 className="text-xl font-bold text-center">Apagar Registro?</h3>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowDeleteModal(false)} className="py-3 rounded-xl bg-slate-800">Voltar</button>
              <button onClick={executeDelete} className="py-3 rounded-xl bg-red-600">Sim, apagar</button>
            </div>
          </div>
        </div>
      )}

      {showResetModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowResetModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6">
            <h3 className="text-xl font-bold text-center">Reiniciar dados?</h3>
            <p className="text-sm text-slate-400 text-center">Isto apagará transações, rendas e custos fixos.</p>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowResetModal(false)} className="py-3 rounded-xl bg-slate-800">Cancelar</button>
              <button onClick={handleResetData} className="py-3 rounded-xl bg-red-600">Reiniciar</button>
            </div>
          </div>
        </div>
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-950/80 backdrop-blur-md border-t border-slate-900 py-3 flex justify-center items-center text-[10px] tracking-[0.2em] text-slate-600 uppercase">
        © 2024 Finmo - Gestão de Gastos Fixos Ativada
      </footer>
    </div>
  );
};

