import { GoogleGenAI, Type } from "@google/genai";
import { Transaction, CategoryType, BudgetStats } from "../types";

// Always use process.env.API_KEY directly for initialization
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getFinancialAdvice = async (
  stats: BudgetStats,
  transactions: Transaction[],
  totalIncome: number
) => {
  const prompt = `
    Atue como Finmo, um mentor financeiro especializado na regra 50/30/20. 
    Analise os seguintes dados financeiros do usuário (Moeda: Metical - MT):

    Renda Total Disponível: ${stats.totalIncome} MT (Base: ${stats.baseIncome} + Variável: ${stats.variableIncome})

    // Fix: Changed stats.needs to stats.totalNeeds as defined in BudgetStats type
    Gastos em Necessidades (Meta 50% de ${stats.totalIncome}): ${stats.totalNeeds + stats.debtInterest + stats.debtNoInterest} MT
    Dívidas Ativas: ${stats.debtInterest + stats.debtNoInterest} MT
    Gastos em Desejos (Meta 30% de ${stats.totalIncome}): ${stats.wants} MT
    Investimentos/Reserva (Meta 20% de ${stats.totalIncome}): ${stats.savings} MT

    Lista de movimentações recentes:
    ${transactions.slice(0, 15).map(t => `- ${t.category === 'INCOME' ? 'ENTRADA' : 'SAÍDA'}: ${t.description} - ${t.amount} MT (${t.subcategory})`).join('\n')}

    Sua resposta deve ser em JSON seguindo este esquema:
    {
      "status": "good" | "warning" | "critical",
      "message": "Uma mensagem curta, pragmática e incentivadora.",
      "recommendations": ["Recomendação 1", "Recomendação 2", "Recomendação 3"]
    }

    Regras de Mentoria:
    1. Se houver Renda Variável expressiva, sugira alocar 100% dela para a Reserva de Emergência ou Dívidas se o usuário estiver fora das metas.
    2. Se Necessidades + Dívidas > 50% da renda total, status é 'critical'.
    3. Fale sempre em Meticais (MT). Seja direto e encorajador.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING },
            message: { type: Type.STRING },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["status", "message", "recommendations"]
        }
      }
    });

    // Accessing the .text property directly as it returns the string output
    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Erro ao obter conselho da IA:", error);
    return {
      status: 'warning',
      message: 'Houve um erro na análise, mas continue monitorando suas entradas variáveis para acelerar sua independência.',
      recommendations: ['Mantenha o registro de proveniência', 'Não gaste a renda extra antes de recebê-la', 'Foco na reserva']
    };
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PlusIcon, 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon,
  TagIcon,
  AlertTriangleIcon,
  XIcon,
  RotateCcwIcon,
  CalendarIcon,
  ArrowRightIcon,
  FlameIcon,
  HandCoinsIcon,
  ClockIcon,
  ArrowDownLeftIcon,
  ArrowUpRightIcon,
  BanknoteIcon,
  RepeatIcon,
  Settings2Icon
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice, FixedExpense } from './types';
import { CURRENCY, CATEGORY_LABELS, CATEGORY_COLORS, SUBCATEGORIES, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  // Persistence states
  const [baseIncome, setBaseIncome] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_income');
    return saved ? Number(saved) : 30000;
  });

  const [fixedExpenses, setFixedExpenses] = useState<FixedExpense[]>(() => {
    const saved = localStorage.getItem('finmo_fixed');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finmo_transactions');
    try {
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Erro ao carregar transações:", e);
      return [];
    }
  });

  // UI / Form states
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [formType, setFormType] = useState<'expense' | 'income' | 'fixed'>('expense');
  const [category, setCategory] = useState<CategoryType>(CategoryType.NEED);
  const [subcategory, setSubcategory] = useState<string>(SUBCATEGORIES[CategoryType.NEED][0]);
  const [dueDate, setDueDate] = useState('');
  const [aiAdvice, setAiAdvice] = useState<AIAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [showFixedManager, setShowFixedManager] = useState(false);

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [transactionToDelete, setTransactionToDelete] = useState<string | null>(null);
  const [showResetModal, setShowResetModal] = useState(false);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('finmo_income', baseIncome.toString()), [baseIncome]);
  useEffect(() => localStorage.setItem('finmo_fixed', JSON.stringify(fixedExpenses)), [fixedExpenses]);
  useEffect(() => localStorage.setItem('finmo_transactions', JSON.stringify(transactions)), [transactions]);

  // Adjust category based on form type
  useEffect(() => {
    if (formType === 'income') setCategory(CategoryType.INCOME);
    else if (formType === 'fixed') setCategory(CategoryType.NEED);
    else if (category === CategoryType.INCOME) setCategory(CategoryType.NEED);
  }, [formType]);

  useEffect(() => {
    setSubcategory(SUBCATEGORIES[category][0]);
    if (category !== CategoryType.DEBT_INTEREST && category !== CategoryType.DEBT_NO_INTEREST) {
      setDueDate('');
    }
  }, [category]);

  const stats = useMemo<BudgetStats>(() => {
    const s: BudgetStats = { 
      baseIncome, 
      variableIncome: 0, 
      totalIncome: 0,
      fixedNeeds: 0,
      variableNeeds: 0,
      totalNeeds: 0,
      wants: 0,
      fixedWants: 0,
      savings: 0, 
      debtInterest: 0, 
      debtNoInterest: 0, 
      fixedDebts: 0,
      totalSpent: 0 
    };

    // 1. Process Fixed Expenses (Baseline)
    fixedExpenses.forEach(fe => {
      if (fe.category === CategoryType.NEED) s.fixedNeeds += fe.amount;
      if (fe.category === CategoryType.WANT) s.fixedWants += fe.amount;
      if (fe.category === CategoryType.DEBT_NO_INTEREST) s.fixedDebts += fe.amount;
    });

    // 2. Process Variable Transactions
    transactions.forEach(t => {
      if (t.category === CategoryType.INCOME) {
        s.variableIncome += t.amount;
      } else {
        if (t.category === CategoryType.NEED) s.variableNeeds += t.amount;
        if (t.category === CategoryType.WANT) s.wants += t.amount;
        if (t.category === CategoryType.SAVING) s.savings += t.amount;
        if (t.category === CategoryType.DEBT_INTEREST) s.debtInterest += t.amount;
        if (t.category === CategoryType.DEBT_NO_INTEREST) s.debtNoInterest += t.amount;
      }
    });

    s.totalIncome = s.baseIncome + s.variableIncome;
    s.totalNeeds = s.fixedNeeds + s.variableNeeds;
    s.totalSpent = s.totalNeeds + s.wants + s.fixedWants + s.savings + s.debtInterest + s.debtNoInterest + s.fixedDebts;

    return s;
  }, [transactions, baseIncome, fixedExpenses]);

  const targets = {
    [CategoryType.NEED]: stats.totalIncome * 0.5,
    [CategoryType.WANT]: stats.totalIncome * 0.3,
    [CategoryType.SAVING]: stats.totalIncome * 0.2,
  };

  const chartData = [
    { name: 'Essenciais*', real: stats.totalNeeds + stats.debtInterest + stats.debtNoInterest + stats.fixedDebts, target: targets[CategoryType.NEED], color: CATEGORY_COLORS[CategoryType.NEED] },
    { name: 'Desejos', real: stats.wants + stats.fixedWants, target: targets[CategoryType.WANT], color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', real: stats.savings, target: targets[CategoryType.SAVING], color: CATEGORY_COLORS[CategoryType.SAVING] },
  ];

  const pieData = [
    { name: 'Fixo Essencial', value: stats.fixedNeeds + stats.fixedDebts, color: '#1e40af' },
    { name: 'Variável Essencial', value: stats.variableNeeds + stats.debtInterest + stats.debtNoInterest, color: '#3b82f6' },
    { name: 'Desejos', value: stats.wants + stats.fixedWants, color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', value: stats.savings, color: CATEGORY_COLORS[CategoryType.SAVING] },
    { name: 'Disponível', value: Math.max(0, stats.totalIncome - stats.totalSpent), color: '#334155' },
  ];

  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    const val = parseFloat(amount);

    if (formType === 'fixed') {
      const newFixed: FixedExpense = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        category: category as any
      };
      setFixedExpenses([...fixedExpenses, newFixed]);
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        category,
        subcategory,
        date: new Date().toISOString(),
        dueDate: isDebt(category) ? dueDate : undefined
      };
      setTransactions([newTransaction, ...transactions]);
    }

    setDescription('');
    setAmount('');
    setDueDate('');
  };

  const executeDelete = () => {
    if (transactionToDelete) {
      setTransactions(transactions.filter(t => t.id !== transactionToDelete));
      setTransactionToDelete(null);
      setShowDeleteModal(false);
    }
  };

  // Added handleResetData to clear all local data and states
  const handleResetData = () => {
    setBaseIncome(30000);
    setFixedExpenses([]);
    setTransactions([]);
    setAiAdvice(null);
    setShowResetModal(false);
  };

  const removeFixed = (id: string) => {
    setFixedExpenses(fixedExpenses.filter(fe => fe.id !== id));
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, stats.totalIncome);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  const getProblematicReason = (t: Transaction) => {
    if (t.category === CategoryType.INCOME) return null;
    if (t.dueDate) {
      const due = new Date(t.dueDate);
      const diffDays = Math.ceil((due.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
      if (diffDays >= 0 && diffDays <= 3) return `Vencimento próximo (${diffDays} dias)`;
      if (diffDays < 0) return `Vencimento atrasado`;
    }
    if (t.category === CategoryType.DEBT_INTEREST) return 'Dívida corrói seu patrimônio';
    return null;
  };

  const isDebt = (cat: CategoryType) => cat === CategoryType.DEBT_INTEREST || cat === CategoryType.DEBT_NO_INTEREST;

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 glass border-b border-slate-800 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-500 p-2 rounded-xl shadow-lg shadow-emerald-500/20">
            <WalletIcon className="w-6 h-6 text-slate-900" />
          </div>
          <h1 className="text-2xl font-bold tracking-tight">Finmo</h1>
        </div>

        <div className="flex items-center gap-4 sm:gap-8">
          <button 
            onClick={() => setShowFixedManager(!showFixedManager)}
            className={`p-2 rounded-lg transition-all flex items-center gap-2 text-xs font-bold uppercase tracking-widest ${showFixedManager ? 'bg-blue-500 text-white' : 'text-slate-500 hover:text-blue-400'}`}
          >
            <RepeatIcon className="w-4 h-4" />
            <span className="hidden sm:inline">Gastos Fixos</span>
          </button>

          <div className="text-right hidden md:block">
            <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Renda Fixa</p>
            <div className="flex items-center justify-end gap-1">
              <span className="text-xs text-emerald-500/60 font-medium">MT</span>
              <input type="number" value={baseIncome} onChange={(e) => setBaseIncome(Number(e.target.value))} className="bg-transparent text-right font-bold text-emerald-400 focus:outline-none w-24 border-b border-transparent focus:border-emerald-500" />
            </div>
          </div>

          <button onClick={() => setShowResetModal(true)} className="p-2 text-slate-500 hover:text-red-400"><RotateCcwIcon className="w-5 h-5" /></button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        <div className="lg:col-span-8 space-y-8">

          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {[
              { label: 'Essenciais*', val: stats.totalNeeds + stats.debtInterest + stats.debtNoInterest + stats.fixedDebts, fixed: stats.fixedNeeds + stats.fixedDebts, target: targets[CategoryType.NEED], color: 'blue', icon: CreditCardIcon },
              { label: 'Desejos', val: stats.wants + stats.fixedWants, fixed: stats.fixedWants, target: targets[CategoryType.WANT], color: 'purple', icon: PieChartIcon },
              { label: 'Reserva', val: stats.savings, fixed: 0, target: targets[CategoryType.SAVING], color: 'emerald', icon: TrendingUpIcon }
            ].map((card, idx) => {
              const isOver = card.val > card.target;
              return (
                <div key={idx} className={`glass p-6 rounded-3xl space-y-2 border-l-4 transition-all ${isOver ? 'border-red-500 shadow-lg shadow-red-900/10' : `border-${card.color}-500`}`}>
                  <div className="flex justify-between items-start">
                    <p className="text-slate-400 text-sm">{card.label}</p>
                    <card.icon className={`w-4 h-4 ${isOver ? 'text-red-500' : `text-${card.color}-500`}`} />
                  </div>
                  <p className={`text-xl font-bold ${isOver ? 'text-red-400' : ''}`}>{formatCurrency(card.val)}</p>
                  <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden flex">
                    <div className="bg-slate-500 h-full opacity-50" style={{ width: `${Math.min(100, (card.fixed / (card.target || 1)) * 100)}%` }} />
                    <div className={`${isOver ? 'bg-red-500' : `bg-${card.color}-500`} h-full`} style={{ width: `${Math.min(100, ((card.val - card.fixed) / (card.target || 1)) * 100)}%` }} />
                  </div>
                  <div className="flex justify-between text-[9px] text-slate-500 uppercase font-bold">
                    <span>Meta: {formatCurrency(card.target)}</span>
                    {card.fixed > 0 && <span>Comprometido: {Math.round((card.fixed / card.target) * 100)}%</span>}
                  </div>
                </div>
              );
            })}
          </div>

          {/* Fixed Expenses Manager (Conditional) */}
          {showFixedManager && (
            <div className="glass p-6 rounded-3xl animate-in slide-in-from-top-4 duration-300">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold flex items-center gap-2"><RepeatIcon className="w-5 h-5 text-blue-400" /> Gestão de Gastos Fixos</h3>
                <span className="text-xs bg-blue-500/20 text-blue-400 px-3 py-1 rounded-full font-bold">Total: {formatCurrency(stats.fixedNeeds + stats.fixedWants + stats.fixedDebts)}</span>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {fixedExpenses.length === 0 ? (
                  <p className="col-span-full text-center py-8 text-slate-500 italic text-sm">Nenhum gasto fixo registado. Adicione via formulário!</p>
                ) : (
                  fixedExpenses.map(fe => (
                    <div key={fe.id} className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800 flex justify-between items-center">
                      <div>
                        <p className="text-sm font-bold">{fe.description}</p>
                        <p className="text-[10px] text-slate-500 uppercase tracking-tighter">{CATEGORY_LABELS[fe.category]}</p>
                      </div>
                      <div className="flex items-center gap-3">
                        <span className="text-sm font-black">{formatCurrency(fe.amount)}</span>
                        <button onClick={() => removeFixed(fe.id)} className="text-slate-600 hover:text-red-400 transition-colors"><Trash2Icon className="w-4 h-4" /></button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="glass p-5 rounded-3xl border-l-4 border-emerald-500 bg-emerald-500/5 flex justify-between items-center">
              <div>
                <p className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest">Disponível p/ Gasto Livre</p>
                <p className="text-2xl font-black">{formatCurrency(stats.totalIncome - (stats.fixedNeeds + stats.fixedWants + stats.fixedDebts))}</p>
              </div>
              <BanknoteIcon className="w-8 h-8 text-emerald-500/20" />
            </div>
            <div className="glass p-5 rounded-3xl border-l-4 border-red-500 bg-red-500/5 flex justify-between items-center">
              <div>
                <p className="text-[10px] text-red-400 font-bold uppercase tracking-widest">Custos Fixos Ativos (Burn Rate)</p>
                <p className="text-2xl font-black">{formatCurrency(stats.fixedNeeds + stats.fixedWants + stats.fixedDebts)}</p>
              </div>
              <FlameIcon className="w-8 h-8 text-red-500/20" />
            </div>
          </div>

          <div className="relative overflow-hidden group">
            <div className="absolute -inset-1 bg-gradient-to-r from-emerald-500 to-blue-500 rounded-3xl blur opacity-25"></div>
            <div className="relative glass p-8 rounded-3xl space-y-6">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <div className="bg-emerald-500/20 p-3 rounded-2xl"><SparklesIcon className="w-6 h-6 text-emerald-400" /></div>
                  <h2 className="text-xl font-bold">Conselheiro Finmo</h2>
                </div>
                <button onClick={getMentorship} disabled={loadingAdvice} className="bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold py-2 px-6 rounded-xl transition-all">
                  {loadingAdvice ? "A pensar..." : "Pedir Mentoria"}
                </button>
              </div>
              {aiAdvice && (
                <div className={`p-6 rounded-2xl border-l-4 ${aiAdvice.status === 'critical' ? 'bg-red-500/10 border-red-500' : 'bg-emerald-500/10 border-emerald-500'}`}>
                  <p className="text-lg font-medium mb-4 italic text-slate-200">"{aiAdvice.message}"</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {aiAdvice.recommendations.map((rec, i) => (
                      <div key={i} className="flex items-start gap-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800">
                        <ChevronRightIcon className="w-5 h-5 text-emerald-400 flex-shrink-0 mt-0.5" />
                        <span className="text-sm text-slate-300">{rec}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-4 space-y-8">
          <div className="glass p-6 rounded-3xl sticky top-24">
            <div className="flex gap-2 p-1 bg-slate-900/50 rounded-xl mb-6">
               <button onClick={() => setFormType('expense')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'expense' ? 'bg-slate-800 text-white' : 'text-slate-500'}`}>GASTO</button>
               <button onClick={() => setFormType('fixed')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'fixed' ? 'bg-blue-500 text-white' : 'text-slate-500'}`}>FIXO</button>
               <button onClick={() => setFormType('income')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'income' ? 'bg-emerald-500 text-slate-950' : 'text-slate-500'}`}>RENDA</button>
            </div>

            <form onSubmit={handleAddTransaction} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Descrição</label>
                <input type="text" placeholder="Ex: Aluguer" value={description} onChange={(e) => setDescription(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Valor (MT)</label>
                <input type="number" placeholder="0.00" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold" />
              </div>

              {formType !== 'income' && (
                <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Categoria</label>
                  <div className="grid grid-cols-2 gap-2">
                    <button type="button" onClick={() => setCategory(CategoryType.NEED)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.NEED ? 'bg-blue-500/20 border-blue-500 text-blue-400 font-bold' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Necessidade</button>
                    <button type="button" onClick={() => setCategory(CategoryType.WANT)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.WANT ? 'bg-purple-500/20 border-purple-500 text-purple-400 font-bold' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Desejo</button>
                    {formType === 'expense' && (
                      <>
                        <button type="button" onClick={() => setCategory(CategoryType.SAVING)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.SAVING ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400 font-bold' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Reserva</button>
                        <button type="button" onClick={() => setCategory(CategoryType.DEBT_INTEREST)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.DEBT_INTEREST ? 'bg-red-500/20 border-red-500 text-red-400 font-bold' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Dívida</button>
                      </>
                    )}
                  </div>
                </div>
              )}

              {formType !== 'fixed' && (
                <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Proveniência/Subcat</label>
                  <select value={subcategory} onChange={(e) => setSubcategory(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 outline-none text-sm appearance-none">
                    {SUBCATEGORIES[category].map((sub) => <option key={sub} value={sub}>{sub}</option>)}
                  </select>
                </div>
              )}

              <button type="submit" className={`w-full font-bold py-3 rounded-xl transition-all shadow-lg ${formType === 'income' ? 'bg-emerald-500 text-slate-950' : formType === 'fixed' ? 'bg-blue-500 text-white' : 'bg-white text-slate-950'}`}>
                {formType === 'fixed' ? 'Salvar Gasto Fixo' : formType === 'income' ? 'Catalogar Renda' : 'Catalogar Gasto'}
              </button>
            </form>
          </div>

          <div className="glass p-6 rounded-3xl min-h-[400px]">
            <h3 className="text-sm font-bold mb-6 text-slate-400 uppercase tracking-widest flex items-center gap-2"><ClockIcon className="w-4 h-4" /> Movimentações Variáveis</h3>
            <div className="space-y-4">
              {transactions.length === 0 ? (
                <p className="text-center py-20 text-slate-600 text-sm italic">Nenhum gasto variável hoje.</p>
              ) : (
                transactions.map((t) => {
                  const alertReason = getProblematicReason(t);
                  const isInc = t.category === CategoryType.INCOME;
                  return (
                    <div key={t.id} className={`group relative p-4 rounded-2xl border transition-all ${isInc ? 'bg-emerald-500/5 border-emerald-500/20' : alertReason ? 'bg-red-500/10 border-red-500/30' : 'bg-slate-900/50 border-transparent hover:border-slate-800'}`}>
                      <div className={`absolute left-0 top-0 bottom-0 w-1 ${isInc ? 'bg-emerald-500' : CATEGORY_COLORS[t.category]}`} />
                      <div className="flex justify-between items-start">
                        <div>
                          <p className="text-sm font-bold">{t.description}</p>
                          <p className="text-[10px] text-slate-500 mt-1">{new Date(t.date).toLocaleDateString()} • {t.subcategory}</p>
                        </div>
                        <div className="flex items-center gap-3">
                           <span className={`font-black text-sm ${isInc ? 'text-emerald-400' : 'text-slate-100'}`}>{isInc ? '+' : '-'}{formatCurrency(t.amount)}</span>
                           <button onClick={() => { setTransactionToDelete(t.id); setShowDeleteModal(true); }} className="opacity-0 group-hover:opacity-100 p-1.5 text-slate-600 hover:text-red-400 transition-all"><Trash2Icon className="w-4 h-4" /></button>
                        </div>
                      </div>
                      {alertReason && <p className="text-[9px] font-black text-red-400 uppercase mt-2">ALERTA: {alertReason}</p>}
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>
      </main>

      {showDeleteModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowDeleteModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6">
            <h3 className="text-xl font-bold text-center">Apagar Registro?</h3>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowDeleteModal(false)} className="py-3 rounded-xl bg-slate-800">Voltar</button>
              <button onClick={executeDelete} className="py-3 rounded-xl bg-red-600">Sim, apagar</button>
            </div>
          </div>
        </div>
      )}

      {showResetModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowResetModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6">
            <h3 className="text-xl font-bold text-center">Reiniciar dados?</h3>
            <p className="text-sm text-slate-400 text-center">Isto apagará transações, rendas e custos fixos.</p>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowResetModal(false)} className="py-3 rounded-xl bg-slate-800">Cancelar</button>
              <button onClick={handleResetData} className="py-3 rounded-xl bg-red-600">Reiniciar</button>
            </div>
          </div>
        </div>
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-950/80 backdrop-blur-md border-t border-slate-900 py-3 flex justify-center items-center text-[10px] tracking-[0.2em] text-slate-600 uppercase">
        © 2024 Finmo - Gestão de Gastos Fixos Ativada
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PlusIcon, 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon,
  TagIcon,
  AlertTriangleIcon,
  XIcon,
  RotateCcwIcon,
  CalendarIcon,
  ArrowRightIcon,
  FlameIcon,
  HandCoinsIcon,
  ClockIcon,
  ArrowDownLeftIcon,
  ArrowUpRightIcon,
  BanknoteIcon,
  RepeatIcon,
  Settings2Icon
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice, FixedExpense } from './types';
import { CURRENCY, CATEGORY_LABELS, CATEGORY_COLORS, SUBCATEGORIES, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  // Persistence states
  const [baseIncome, setBaseIncome] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_income');
    return saved ? Number(saved) : 30000;
  });

  const [payday, setPayday] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_payday');
    return saved ? Number(saved) : 1;
  });

  const [fixedExpenses, setFixedExpenses] = useState<FixedExpense[]>(() => {
    const saved = localStorage.getItem('finmo_fixed');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finmo_transactions');
    try {
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Erro ao carregar transações:", e);
      return [];
    }
  });

  // UI / Form states
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [formType, setFormType] = useState<'expense' | 'income' | 'fixed'>('expense');
  const [category, setCategory] = useState<CategoryType>(CategoryType.NEED);
  const [subcategory, setSubcategory] = useState<string>(SUBCATEGORIES[CategoryType.NEED][0]);
  const [dueDate, setDueDate] = useState('');
  const [aiAdvice, setAiAdvice] = useState<AIAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [showFixedManager, setShowFixedManager] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [transactionToDelete, setTransactionToDelete] = useState<string | null>(null);
  const [showResetModal, setShowResetModal] = useState(false);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('finmo_income', baseIncome.toString()), [baseIncome]);
  useEffect(() => localStorage.setItem('finmo_payday', payday.toString()), [payday]);
  useEffect(() => localStorage.setItem('finmo_fixed', JSON.stringify(fixedExpenses)), [fixedExpenses]);
  useEffect(() => localStorage.setItem('finmo_transactions', JSON.stringify(transactions)), [transactions]);

  // Adjust category based on form type
  useEffect(() => {
    if (formType === 'income') setCategory(CategoryType.INCOME);
    else if (formType === 'fixed') setCategory(CategoryType.NEED);
    else if (category === CategoryType.INCOME) setCategory(CategoryType.NEED);
  }, [formType]);

  useEffect(() => {
    setSubcategory(SUBCATEGORIES[category][0]);
    if (category !== CategoryType.DEBT_INTEREST && category !== CategoryType.DEBT_NO_INTEREST) {
      setDueDate('');
    }
  }, [category]);

  const stats = useMemo<BudgetStats>(() => {
    const s: BudgetStats = { 
      baseIncome, 
      variableIncome: 0, 
      totalIncome: 0,
      fixedNeeds: 0,
      variableNeeds: 0,
      totalNeeds: 0,
      wants: 0,
      fixedWants: 0,
      savings: 0, 
      debtInterest: 0, 
      debtNoInterest: 0, 
      fixedDebts: 0,
      totalSpent: 0 
    };

    fixedExpenses.forEach(fe => {
      if (fe.category === CategoryType.NEED) s.fixedNeeds += fe.amount;
      if (fe.category === CategoryType.WANT) s.fixedWants += fe.amount;
      if (fe.category === CategoryType.DEBT_NO_INTEREST) s.fixedDebts += fe.amount;
    });

    transactions.forEach(t => {
      if (t.category === CategoryType.INCOME) {
        s.variableIncome += t.amount;
      } else {
        if (t.category === CategoryType.NEED) s.variableNeeds += t.amount;
        if (t.category === CategoryType.WANT) s.wants += t.amount;
        if (t.category === CategoryType.SAVING) s.savings += t.amount;
        if (t.category === CategoryType.DEBT_INTEREST) s.debtInterest += t.amount;
        if (t.category === CategoryType.DEBT_NO_INTEREST) s.debtNoInterest += t.amount;
      }
    });

    s.totalIncome = s.baseIncome + s.variableIncome;
    s.totalNeeds = s.fixedNeeds + s.variableNeeds;
    s.totalSpent = s.totalNeeds + s.wants + s.fixedWants + s.savings + s.debtInterest + s.debtNoInterest + s.fixedDebts;

    return s;
  }, [transactions, baseIncome, fixedExpenses]);

  const targets = {
    [CategoryType.NEED]: stats.totalIncome * 0.5,
    [CategoryType.WANT]: stats.totalIncome * 0.3,
    [CategoryType.SAVING]: stats.totalIncome * 0.2,
  };

  const chartData = [
    { name: 'Essenciais*', real: stats.totalNeeds + stats.debtInterest + stats.debtNoInterest + stats.fixedDebts, target: targets[CategoryType.NEED], color: CATEGORY_COLORS[CategoryType.NEED] },
    { name: 'Desejos', real: stats.wants + stats.fixedWants, target: targets[CategoryType.WANT], color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', real: stats.savings, target: targets[CategoryType.SAVING], color: CATEGORY_COLORS[CategoryType.SAVING] },
  ];

  const pieData = [
    { name: 'Fixo Essencial', value: stats.fixedNeeds + stats.fixedDebts, color: '#1e40af' },
    { name: 'Variável Essencial', value: stats.variableNeeds + stats.debtInterest + stats.debtNoInterest, color: '#3b82f6' },
    { name: 'Desejos', value: stats.wants + stats.fixedWants, color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', value: stats.savings, color: CATEGORY_COLORS[CategoryType.SAVING] },
    { name: 'Disponível', value: Math.max(0, stats.totalIncome - stats.totalSpent), color: '#334155' },
  ];

  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    const val = parseFloat(amount);

    if (formType === 'fixed') {
      const newFixed: FixedExpense = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        category: category as any
      };
      setFixedExpenses([...fixedExpenses, newFixed]);
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        category,
        subcategory,
        date: new Date().toISOString(),
        dueDate: isDebt(category) ? dueDate : undefined
      };
      setTransactions([newTransaction, ...transactions]);
    }

    setDescription('');
    setAmount('');
    setDueDate('');
  };

  const executeDelete = () => {
    if (transactionToDelete) {
      setTransactions(transactions.filter(t => t.id !== transactionToDelete));
      setTransactionToDelete(null);
      setShowDeleteModal(false);
    }
  };

  const handleResetData = () => {
    setBaseIncome(30000);
    setPayday(1);
    setFixedExpenses([]);
    setTransactions([]);
    setAiAdvice(null);
    setShowResetModal(false);
  };

  const removeFixed = (id: string) => {
    setFixedExpenses(fixedExpenses.filter(fe => fe.id !== id));
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, stats.totalIncome);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  const isDebt = (cat: CategoryType) => cat === CategoryType.DEBT_INTEREST || cat === CategoryType.DEBT_NO_INTEREST;

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 glass border-b border-slate-800 px-4 md:px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-500 p-2 rounded-xl shadow-lg shadow-emerald-500/20">
            <WalletIcon className="w-5 h-5 md:w-6 md:h-6 text-slate-900" />
          </div>
          <h1 className="text-xl md:text-2xl font-bold tracking-tight">Finmo</h1>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
          <button 
            onClick={() => setShowFixedManager(!showFixedManager)}
            className={`p-2 rounded-lg transition-all flex items-center gap-2 text-[10px] md:text-xs font-bold uppercase tracking-widest ${showFixedManager ? 'bg-blue-500 text-white' : 'text-slate-500 hover:text-blue-400'}`}
          >
            <RepeatIcon className="w-4 h-4" />
            <span className="hidden sm:inline">Gastos Fixos</span>
          </button>

          {/* Settings Button - Crucial for Mobile */}
          <button 
            onClick={() => setShowSettings(true)}
            className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg text-slate-300 transition-all flex items-center gap-2"
          >
            <Settings2Icon className="w-4 h-4 md:w-5 md:h-5" />
            <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Ajustes</span>
          </button>

          <button onClick={() => setShowResetModal(true)} className="p-2 text-slate-500 hover:text-red-400 transition-colors">
            <RotateCcwIcon className="w-5 h-5" />
          </button>
        </div>
      </header>

      {/* Settings Modal (Mobile & Desktop Access) */}
      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-sm" onClick={() => setShowSettings(false)} />
          <div className="relative glass p-6 md:p-8 rounded-3xl max-w-sm w-full space-y-6 shadow-2xl border-slate-700 animate-in zoom-in duration-200">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold flex items-center gap-2">
                <Settings2Icon className="w-5 h-5 text-emerald-400" />
                Configuração Base
              </h3>
              <button onClick={() => setShowSettings(false)} className="p-1 hover:bg-slate-800 rounded-lg transition-colors">
                <XIcon className="w-5 h-5 text-slate-500" />
              </button>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Renda Fixa Mensal (Base)</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-500 font-bold text-xs">MT</span>
                  <input 
                    type="number" 
                    value={baseIncome} 
                    onChange={(e) => setBaseIncome(Number(e.target.value))} 
                    className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-400 font-bold" 
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Dia do Salário</label>
                <div className="relative">
                  <CalendarIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                  <input 
                    type="number" 
                    min="1" 
                    max="31"
                    value={payday} 
                    onChange={(e) => setPayday(Number(e.target.value))} 
                    className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none text-slate-200 font-bold" 
                  />
                </div>
                <p className="text-[9px] text-slate-500 ml-1">Usado para calcular ciclos de gastos.</p>
              </div>
            </div>

            <button 
              onClick={() => setShowSettings(false)}
              className="w-full bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold py-3 rounded-xl transition-all shadow-lg"
            >
              Confirmar Ajustes
            </button>
          </div>
        </div>
      )}

      <main className="max-w-6xl mx-auto p-4 lg:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        <div className="lg:col-span-8 space-y-8">

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {[
              { label: 'Essenciais*', val: stats.totalNeeds + stats.debtInterest + stats.debtNoInterest + stats.fixedDebts, fixed: stats.fixedNeeds + stats.fixedDebts, target: targets[CategoryType.NEED], color: 'blue', icon: CreditCardIcon },
              { label: 'Desejos', val: stats.wants + stats.fixedWants, fixed: stats.fixedWants, target: targets[CategoryType.WANT], color: 'purple', icon: PieChartIcon },
              { label: 'Reserva', val: stats.savings, fixed: 0, target: targets[CategoryType.SAVING], color: 'emerald', icon: TrendingUpIcon }
            ].map((card, idx) => {
              const isOver = card.val > card.target;
              return (
                <div key={idx} className={`glass p-6 rounded-3xl space-y-2 border-l-4 transition-all ${isOver ? 'border-red-500 shadow-lg shadow-red-900/10' : `border-${card.color}-500`}`}>
                  <div className="flex justify-between items-start">
                    <p className="text-slate-400 text-sm">{card.label}</p>
                    <card.icon className={`w-4 h-4 ${isOver ? 'text-red-500' : `text-${card.color}-500`}`} />
                  </div>
                  <p className={`text-xl font-bold ${isOver ? 'text-red-400' : ''}`}>{formatCurrency(card.val)}</p>
                  <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden flex">
                    <div className="bg-slate-500 h-full opacity-50" style={{ width: `${Math.min(100, (card.fixed / (card.target || 1)) * 100)}%` }} />
                    <div className={`${isOver ? 'bg-red-500' : `bg-${card.color}-500`} h-full`} style={{ width: `${Math.min(100, ((card.val - card.fixed) / (card.target || 1)) * 100)}%` }} />
                  </div>
                  <div className="flex justify-between text-[9px] text-slate-500 uppercase font-bold">
                    <span>Meta: {formatCurrency(card.target)}</span>
                    {card.fixed > 0 && <span>Comprometido: {Math.round((card.fixed / card.target) * 100)}%</span>}
                  </div>
                </div>
              );
            })}
          </div>

          {showFixedManager && (
            <div className="glass p-6 rounded-3xl animate-in slide-in-from-top-4 duration-300">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold flex items-center gap-2"><RepeatIcon className="w-5 h-5 text-blue-400" /> Gestão de Gastos Fixos</h3>
                <span className="text-xs bg-blue-500/20 text-blue-400 px-3 py-1 rounded-full font-bold">Total: {formatCurrency(stats.fixedNeeds + stats.fixedWants + stats.fixedDebts)}</span>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {fixedExpenses.length === 0 ? (
                  <p className="col-span-full text-center py-8 text-slate-500 italic text-sm">Nenhum gasto fixo registado. Adicione via formulário!</p>
                ) : (
                  fixedExpenses.map(fe => (
                    <div key={fe.id} className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800 flex justify-between items-center">
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-bold truncate">{fe.description}</p>
                        <p className="text-[10px] text-slate-500 uppercase tracking-tighter">{CATEGORY_LABELS[fe.category]}</p>
                      </div>
                      <div className="flex items-center gap-3 ml-4">
                        <span className="text-sm font-black whitespace-nowrap">{formatCurrency(fe.amount)}</span>
                        <button onClick={() => removeFixed(fe.id)} className="text-slate-600 hover:text-red-400 transition-colors"><Trash2Icon className="w-4 h-4" /></button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="glass p-5 rounded-3xl border-l-4 border-emerald-500 bg-emerald-500/5 flex justify-between items-center group">
              <div>
                <p className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest flex items-center gap-1">
                  Disponível p/ Gasto Livre <ArrowRightIcon className="w-3 h-3 opacity-0 group-hover:opacity-100 transition-all translate-x-[-4px] group-hover:translate-x-0" />
                </p>
                <p className="text-2xl font-black">{formatCurrency(stats.totalIncome - (stats.fixedNeeds + stats.fixedWants + stats.fixedDebts))}</p>
              </div>
              <BanknoteIcon className="w-8 h-8 text-emerald-500/20" />
            </div>
            <div className="glass p-5 rounded-3xl border-l-4 border-red-500 bg-red-500/5 flex justify-between items-center">
              <div>
                <p className="text-[10px] text-red-400 font-bold uppercase tracking-widest">Compromissos Fixos (Mês)</p>
                <p className="text-2xl font-black">{formatCurrency(stats.fixedNeeds + stats.fixedWants + stats.fixedDebts)}</p>
              </div>
              <FlameIcon className="w-8 h-8 text-red-500/20" />
            </div>
          </div>

          <div className="relative overflow-hidden group">
            <div className="absolute -inset-1 bg-gradient-to-r from-emerald-500 to-blue-500 rounded-3xl blur opacity-25"></div>
            <div className="relative glass p-6 md:p-8 rounded-3xl space-y-6">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div className="flex items-center gap-3">
                  <div className="bg-emerald-500/20 p-3 rounded-2xl"><SparklesIcon className="w-6 h-6 text-emerald-400" /></div>
                  <div>
                    <h2 className="text-xl font-bold">Mentor Finmo</h2>
                    <p className="text-xs text-slate-500">Inteligência pragmática em tempo real</p>
                  </div>
                </div>
                <button 
                  onClick={getMentorship} 
                  disabled={loadingAdvice} 
                  className="w-full md:w-auto bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold py-2.5 px-6 rounded-xl transition-all flex items-center justify-center gap-2"
                >
                  {loadingAdvice ? (
                    <>
                      <div className="w-4 h-4 border-2 border-slate-950/20 border-t-slate-950 rounded-full animate-spin" />
                      Analisando...
                    </>
                  ) : "Pedir Mentoria"}
                </button>
              </div>
              {aiAdvice && (
                <div className={`p-6 rounded-2xl border-l-4 animate-in fade-in slide-in-from-bottom-2 ${aiAdvice.status === 'critical' ? 'bg-red-500/10 border-red-500' : 'bg-emerald-500/10 border-emerald-500'}`}>
                  <p className="text-base md:text-lg font-medium mb-4 italic text-slate-200 leading-relaxed">"{aiAdvice.message}"</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {aiAdvice.recommendations.map((rec, i) => (
                      <div key={i} className="flex items-start gap-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800">
                        <ChevronRightIcon className="w-4 h-4 text-emerald-400 flex-shrink-0 mt-0.5" />
                        <span className="text-sm text-slate-300">{rec}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-4 space-y-8">
          <div className="glass p-5 md:p-6 rounded-3xl sticky top-24">
            <div className="flex gap-2 p-1 bg-slate-900/50 rounded-xl mb-6">
               <button onClick={() => setFormType('expense')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'expense' ? 'bg-slate-800 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>GASTO</button>
               <button onClick={() => setFormType('fixed')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'fixed' ? 'bg-blue-500 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>FIXO</button>
               <button onClick={() => setFormType('income')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'income' ? 'bg-emerald-500 text-slate-950 shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>RENDA</button>
            </div>

            <form onSubmit={handleAddTransaction} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Descrição</label>
                <input 
                  type="text" 
                  placeholder={formType === 'fixed' ? "Ex: Aluguer" : formType === 'income' ? "Ex: Bonus" : "Ex: Café"} 
                  value={description} 
                  onChange={(e) => setDescription(e.target.value)} 
                  className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all placeholder:text-slate-700" 
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Valor (MT)</label>
                <input 
                  type="number" 
                  placeholder="0.00" 
                  value={amount} 
                  onChange={(e) => setAmount(e.target.value)} 
                  className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold text-slate-100" 
                />
              </div>

              {formType !== 'income' && (
                <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Categoria</label>
                  <div className="grid grid-cols-2 gap-2">
                    <button type="button" onClick={() => setCategory(CategoryType.NEED)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.NEED ? 'bg-blue-500/20 border-blue-500 text-blue-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Necessidade</button>
                    <button type="button" onClick={() => setCategory(CategoryType.WANT)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.WANT ? 'bg-purple-500/20 border-purple-500 text-purple-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Desejo</button>
                    {formType === 'expense' && (
                      <>
                        <button type="button" onClick={() => setCategory(CategoryType.SAVING)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.SAVING ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Reserva</button>
                        <button type="button" onClick={() => setCategory(CategoryType.DEBT_INTEREST)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.DEBT_INTEREST ? 'bg-red-500/20 border-red-500 text-red-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Dívida</button>
                      </>
                    )}
                  </div>
                </div>
              )}

              {formType !== 'fixed' && (
                <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Proveniência/Subcat</label>
                  <div className="relative">
                    <select 
                      value={subcategory} 
                      onChange={(e) => setSubcategory(e.target.value)} 
                      className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 outline-none text-sm appearance-none focus:ring-2 focus:ring-blue-500 transition-all cursor-pointer"
                    >
                      {SUBCATEGORIES[category].map((sub) => <option key={sub} value={sub}>{sub}</option>)}
                    </select>
                    <ChevronRightIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 rotate-90 pointer-events-none" />
                  </div>
                </div>
              )}

              <button type="submit" className={`w-full font-bold py-3.5 rounded-xl transition-all shadow-lg active:scale-[0.98] ${formType === 'income' ? 'bg-emerald-500 text-slate-950 hover:bg-emerald-400' : formType === 'fixed' ? 'bg-blue-500 text-white hover:bg-blue-400' : 'bg-white text-slate-950 hover:bg-slate-100'}`}>
                {formType === 'fixed' ? 'Salvar Gasto Fixo' : formType === 'income' ? 'Catalogar Renda' : 'Catalogar Gasto'}
              </button>
            </form>
          </div>

          <div className="glass p-5 md:p-6 rounded-3xl min-h-[400px]">
            <h3 className="text-sm font-bold mb-6 text-slate-400 uppercase tracking-widest flex items-center gap-2"><ClockIcon className="w-4 h-4" /> Atividade Recente</h3>
            <div className="space-y-3">
              {transactions.length === 0 ? (
                <div className="text-center py-20">
                  <PieChartIcon className="w-10 h-10 text-slate-800 mx-auto mb-3" />
                  <p className="text-slate-600 text-xs italic">Nenhum registro variável.</p>
                </div>
              ) : (
                transactions.map((t) => {
                  const isInc = t.category === CategoryType.INCOME;
                  return (
                    <div key={t.id} className={`group relative p-4 rounded-2xl border transition-all ${isInc ? 'bg-emerald-500/5 border-emerald-500/20' : 'bg-slate-900/50 border-transparent hover:border-slate-800'}`}>
                      <div className={`absolute left-0 top-0 bottom-0 w-1 rounded-l-full ${isInc ? 'bg-emerald-500' : CATEGORY_COLORS[t.category]}`} />
                      <div className="flex justify-between items-start">
                        <div className="min-w-0 pr-2">
                          <p className="text-sm font-bold truncate">{t.description}</p>
                          <p className="text-[10px] text-slate-500 mt-1 flex items-center gap-1.5 whitespace-nowrap overflow-hidden">
                             <TagIcon className="w-2.5 h-2.5" /> {t.subcategory} • {new Date(t.date).toLocaleDateString()}
                          </p>
                        </div>
                        <div className="flex items-center gap-2 flex-shrink-0">
                           <span className={`font-black text-sm whitespace-nowrap ${isInc ? 'text-emerald-400' : 'text-slate-100'}`}>{isInc ? '+' : '-'}{formatCurrency(t.amount)}</span>
                           <button onClick={() => { setTransactionToDelete(t.id); setShowDeleteModal(true); }} className="p-1.5 text-slate-600 hover:text-red-400 transition-all"><Trash2Icon className="w-4 h-4" /></button>
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>
      </main>

      {/* Reusable Modals */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowDeleteModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6 animate-in zoom-in duration-200">
             <div className="flex justify-center"><AlertTriangleIcon className="w-12 h-12 text-red-500" /></div>
            <h3 className="text-xl font-bold text-center">Apagar Registro?</h3>
            <p className="text-sm text-slate-400 text-center">Isto atualizará instantaneamente suas metas 50/30/20.</p>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowDeleteModal(false)} className="py-3 rounded-xl bg-slate-800 text-slate-300 font-bold">Voltar</button>
              <button onClick={executeDelete} className="py-3 rounded-xl bg-red-600 text-white font-bold">Apagar</button>
            </div>
          </div>
        </div>
      )}

      {showResetModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowResetModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6 animate-in zoom-in duration-200 text-center">
            <RotateCcwIcon className="w-12 h-12 text-orange-500 mx-auto" />
            <h3 className="text-xl font-bold">Recomeçar Tudo?</h3>
            <p className="text-sm text-slate-400">Dados de transações, rendas e custos fixos serão permanentemente apagados.</p>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowResetModal(false)} className="py-3 rounded-xl bg-slate-800 font-bold">Cancelar</button>
              <button onClick={handleResetData} className="py-3 rounded-xl bg-orange-600 font-bold">Sim, Reset</button>
            </div>
          </div>
        </div>
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-950/90 backdrop-blur-md border-t border-slate-900 py-3 px-4 flex justify-center items-center text-[9px] md:text-[10px] tracking-[0.2em] text-slate-600 uppercase text-center">
        Finmo • Gestão Inteligente em Meticais • {new Date().getFullYear()}
      </footer>
    </div>
  );
};

export default App;

export enum CategoryType {
  NEED = 'NEED',      // 50%
  WANT = 'WANT',      // 30%
  SAVING = 'SAVING',  // 20%
  DEBT_INTEREST = 'DEBT_INTEREST',
  DEBT_NO_INTEREST = 'DEBT_NO_INTEREST',
  INCOME = 'INCOME'   // Variable/Extra Income
}

export interface FixedExpense {
  id: string;
  description: string;
  amount: number;
  category: CategoryType.NEED | CategoryType.WANT | CategoryType.DEBT_NO_INTEREST;
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  interestAmount?: number; // New field for tracking interest costs in debts
  category: CategoryType;
  subcategory: string;
  date: string;
  dueDate?: string;
}

export interface BudgetStats {
  baseIncome: number;
  variableIncome: number;
  totalIncome: number;
  fixedNeeds: number;
  variableNeeds: number;
  totalNeeds: number;
  wants: number;
  fixedWants: number;
  savings: number;
  debtInterest: number;
  debtNoInterest: number;
  fixedDebts: number;
  totalSpent: number;
}

export interface AIAdvice {
  status: 'good' | 'warning' | 'critical';
  message: string;
  recommendations: string[];
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PlusIcon, 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon,
  TagIcon,
  AlertTriangleIcon,
  XIcon,
  RotateCcwIcon,
  CalendarIcon,
  ArrowRightIcon,
  FlameIcon,
  HandCoinsIcon,
  ClockIcon,
  ArrowDownLeftIcon,
  ArrowUpRightIcon,
  BanknoteIcon,
  RepeatIcon,
  Settings2Icon,
  InfoIcon
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice, FixedExpense } from './types';
import { CURRENCY, CATEGORY_LABELS, CATEGORY_COLORS, SUBCATEGORIES, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  // Persistence states
  const [baseIncome, setBaseIncome] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_income');
    return saved ? Number(saved) : 30000;
  });

  const [payday, setPayday] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_payday');
    return saved ? Number(saved) : 1;
  });

  const [fixedExpenses, setFixedExpenses] = useState<FixedExpense[]>(() => {
    const saved = localStorage.getItem('finmo_fixed');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finmo_transactions');
    try {
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Erro ao carregar transações:", e);
      return [];
    }
  });

  // UI / Form states
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [interestAmount, setInterestAmount] = useState('');
  const [formType, setFormType] = useState<'expense' | 'income' | 'fixed'>('expense');
  const [category, setCategory] = useState<CategoryType>(CategoryType.NEED);
  const [subcategory, setSubcategory] = useState<string>(SUBCATEGORIES[CategoryType.NEED][0]);
  const [dueDate, setDueDate] = useState('');
  const [aiAdvice, setAiAdvice] = useState<AIAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [showFixedManager, setShowFixedManager] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [transactionToDelete, setTransactionToDelete] = useState<string | null>(null);
  const [showResetModal, setShowResetModal] = useState(false);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('finmo_income', baseIncome.toString()), [baseIncome]);
  useEffect(() => localStorage.setItem('finmo_payday', payday.toString()), [payday]);
  useEffect(() => localStorage.setItem('finmo_fixed', JSON.stringify(fixedExpenses)), [fixedExpenses]);
  useEffect(() => localStorage.setItem('finmo_transactions', JSON.stringify(transactions)), [transactions]);

  // Adjust category based on form type
  useEffect(() => {
    if (formType === 'income') setCategory(CategoryType.INCOME);
    else if (formType === 'fixed') setCategory(CategoryType.NEED);
    else if (category === CategoryType.INCOME) setCategory(CategoryType.NEED);
  }, [formType]);

  useEffect(() => {
    setSubcategory(SUBCATEGORIES[category][0]);
    if (category !== CategoryType.DEBT_INTEREST && category !== CategoryType.DEBT_NO_INTEREST) {
      setDueDate('');
      setInterestAmount('');
    }
  }, [category]);

  const stats = useMemo<BudgetStats>(() => {
    const s: BudgetStats = { 
      baseIncome, 
      variableIncome: 0, 
      totalIncome: 0,
      fixedNeeds: 0,
      variableNeeds: 0,
      totalNeeds: 0,
      wants: 0,
      fixedWants: 0,
      savings: 0, 
      debtInterest: 0, 
      debtNoInterest: 0, 
      fixedDebts: 0,
      totalSpent: 0 
    };

    fixedExpenses.forEach(fe => {
      if (fe.category === CategoryType.NEED) s.fixedNeeds += fe.amount;
      if (fe.category === CategoryType.WANT) s.fixedWants += fe.amount;
      if (fe.category === CategoryType.DEBT_NO_INTEREST) s.fixedDebts += fe.amount;
    });

    transactions.forEach(t => {
      if (t.category === CategoryType.INCOME) {
        s.variableIncome += t.amount;
      } else {
        if (t.category === CategoryType.NEED) s.variableNeeds += t.amount;
        if (t.category === CategoryType.WANT) s.wants += t.amount;
        if (t.category === CategoryType.SAVING) s.savings += t.amount;
        if (t.category === CategoryType.DEBT_INTEREST) s.debtInterest += t.amount;
        if (t.category === CategoryType.DEBT_NO_INTEREST) s.debtNoInterest += t.amount;
      }
    });

    s.totalIncome = s.baseIncome + s.variableIncome;
    s.totalNeeds = s.fixedNeeds + s.variableNeeds;
    s.totalSpent = s.totalNeeds + s.wants + s.fixedWants + s.savings + s.debtInterest + s.debtNoInterest + s.fixedDebts;

    return s;
  }, [transactions, baseIncome, fixedExpenses]);

  const targets = {
    [CategoryType.NEED]: stats.totalIncome * 0.5,
    [CategoryType.WANT]: stats.totalIncome * 0.3,
    [CategoryType.SAVING]: stats.totalIncome * 0.2,
  };

  const chartData = [
    { name: 'Essenciais*', real: stats.totalNeeds + stats.debtInterest + stats.debtNoInterest + stats.fixedDebts, target: targets[CategoryType.NEED], color: CATEGORY_COLORS[CategoryType.NEED] },
    { name: 'Desejos', real: stats.wants + stats.fixedWants, target: targets[CategoryType.WANT], color: CATEGORY_COLORS[CategoryType.WANT] },
    { name: 'Reserva', real: stats.savings, target: targets[CategoryType.SAVING], color: CATEGORY_COLORS[CategoryType.SAVING] },
  ];

  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    const val = parseFloat(amount);

    if (formType === 'fixed') {
      const newFixed: FixedExpense = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        category: category as any
      };
      setFixedExpenses([...fixedExpenses, newFixed]);
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        interestAmount: interestAmount ? parseFloat(interestAmount) : undefined,
        category,
        subcategory,
        date: new Date().toISOString(),
        dueDate: isDebt(category) ? dueDate : undefined
      };
      setTransactions([newTransaction, ...transactions]);
    }

    setDescription('');
    setAmount('');
    setInterestAmount('');
    setDueDate('');
  };

  const executeDelete = () => {
    if (transactionToDelete) {
      setTransactions(transactions.filter(t => t.id !== transactionToDelete));
      setTransactionToDelete(null);
      setShowDeleteModal(false);
    }
  };

  const handleResetData = () => {
    setBaseIncome(30000);
    setPayday(1);
    setFixedExpenses([]);
    setTransactions([]);
    setAiAdvice(null);
    setShowResetModal(false);
  };

  const removeFixed = (id: string) => {
    setFixedExpenses(fixedExpenses.filter(fe => fe.id !== id));
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, stats.totalIncome);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  const isDebt = (cat: CategoryType) => cat === CategoryType.DEBT_INTEREST || cat === CategoryType.DEBT_NO_INTEREST;

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 glass border-b border-slate-800 px-4 md:px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-500 p-2 rounded-xl shadow-lg shadow-emerald-500/20">
            <WalletIcon className="w-5 h-5 md:w-6 md:h-6 text-slate-900" />
          </div>
          <h1 className="text-xl md:text-2xl font-bold tracking-tight">Finmo</h1>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
          <button 
            onClick={() => setShowFixedManager(!showFixedManager)}
            className={`p-2 rounded-lg transition-all flex items-center gap-2 text-[10px] md:text-xs font-bold uppercase tracking-widest ${showFixedManager ? 'bg-blue-500 text-white' : 'text-slate-500 hover:text-blue-400'}`}
          >
            <RepeatIcon className="w-4 h-4" />
            <span className="hidden sm:inline">Gastos Fixos</span>
          </button>

          <button 
            onClick={() => setShowSettings(true)}
            className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg text-slate-300 transition-all flex items-center gap-2"
          >
            <Settings2Icon className="w-4 h-4 md:w-5 md:h-5" />
            <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Ajustes</span>
          </button>

          <button onClick={() => setShowResetModal(true)} className="p-2 text-slate-500 hover:text-red-400 transition-colors">
            <RotateCcwIcon className="w-5 h-5" />
          </button>
        </div>
      </header>

      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-sm" onClick={() => setShowSettings(false)} />
          <div className="relative glass p-6 md:p-8 rounded-3xl max-w-sm w-full space-y-6 shadow-2xl border-slate-700 animate-in zoom-in duration-200">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold flex items-center gap-2">
                <Settings2Icon className="w-5 h-5 text-emerald-400" />
                Configuração Base
              </h3>
              <button onClick={() => setShowSettings(false)} className="p-1 hover:bg-slate-800 rounded-lg transition-colors">
                <XIcon className="w-5 h-5 text-slate-500" />
              </button>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Renda Fixa Mensal (Base)</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-500 font-bold text-xs">MT</span>
                  <input 
                    type="number" 
                    value={baseIncome} 
                    onChange={(e) => setBaseIncome(Number(e.target.value))} 
                    className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-400 font-bold" 
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Dia do Salário</label>
                <div className="relative">
                  <CalendarIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                  <input 
                    type="number" 
                    min="1" 
                    max="31"
                    value={payday} 
                    onChange={(e) => setPayday(Number(e.target.value))} 
                    className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none text-slate-200 font-bold" 
                  />
                </div>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold py-3 rounded-xl transition-all shadow-lg">Confirmar Ajustes</button>
          </div>
        </div>
      )}

      <main className="max-w-6xl mx-auto p-4 lg:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-8 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {[
              { label: 'Essenciais*', val: stats.totalNeeds + stats.debtInterest + stats.debtNoInterest + stats.fixedDebts, fixed: stats.fixedNeeds + stats.fixedDebts, target: targets[CategoryType.NEED], color: 'blue', icon: CreditCardIcon },
              { label: 'Desejos', val: stats.wants + stats.fixedWants, fixed: stats.fixedWants, target: targets[CategoryType.WANT], color: 'purple', icon: PieChartIcon },
              { label: 'Reserva', val: stats.savings, fixed: 0, target: targets[CategoryType.SAVING], color: 'emerald', icon: TrendingUpIcon }
            ].map((card, idx) => {
              const isOver = card.val > card.target;
              return (
                <div key={idx} className={`glass p-6 rounded-3xl space-y-2 border-l-4 transition-all ${isOver ? 'border-red-500 shadow-lg shadow-red-900/10' : `border-${card.color}-500`}`}>
                  <div className="flex justify-between items-start">
                    <p className="text-slate-400 text-sm">{card.label}</p>
                    <card.icon className={`w-4 h-4 ${isOver ? 'text-red-500' : `text-${card.color}-500`}`} />
                  </div>
                  <p className={`text-xl font-bold ${isOver ? 'text-red-400' : ''}`}>{formatCurrency(card.val)}</p>
                  <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden flex">
                    <div className="bg-slate-500 h-full opacity-50" style={{ width: `${Math.min(100, (card.fixed / (card.target || 1)) * 100)}%` }} />
                    <div className={`${isOver ? 'bg-red-500' : `bg-${card.color}-500`} h-full`} style={{ width: `${Math.min(100, ((card.val - card.fixed) / (card.target || 1)) * 100)}%` }} />
                  </div>
                  <div className="flex justify-between text-[9px] text-slate-500 uppercase font-bold">
                    <span>Meta: {formatCurrency(card.target)}</span>
                  </div>
                </div>
              );
            })}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="glass p-5 rounded-3xl border-l-4 border-emerald-500 bg-emerald-500/5 flex justify-between items-center group">
              <div>
                <p className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest">Disponível p/ Gasto Livre</p>
                <p className="text-2xl font-black">{formatCurrency(stats.totalIncome - (stats.fixedNeeds + stats.fixedWants + stats.fixedDebts))}</p>
              </div>
              <BanknoteIcon className="w-8 h-8 text-emerald-500/20" />
            </div>
            <div className="glass p-5 rounded-3xl border-l-4 border-red-500 bg-red-500/5 flex justify-between items-center">
              <div>
                <p className="text-[10px] text-red-400 font-bold uppercase tracking-widest">Compromissos Fixos (Mês)</p>
                <p className="text-2xl font-black">{formatCurrency(stats.fixedNeeds + stats.fixedWants + stats.fixedDebts)}</p>
              </div>
              <FlameIcon className="w-8 h-8 text-red-500/20" />
            </div>
          </div>

          <div className="relative overflow-hidden group">
            <div className="absolute -inset-1 bg-gradient-to-r from-emerald-500 to-blue-500 rounded-3xl blur opacity-25"></div>
            <div className="relative glass p-6 md:p-8 rounded-3xl space-y-6">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div className="flex items-center gap-3">
                  <div className="bg-emerald-500/20 p-3 rounded-2xl"><SparklesIcon className="w-6 h-6 text-emerald-400" /></div>
                  <div>
                    <h2 className="text-xl font-bold">Mentor Finmo</h2>
                    <p className="text-xs text-slate-500">Inteligência pragmática em tempo real</p>
                  </div>
                </div>
                <button onClick={getMentorship} disabled={loadingAdvice} className="w-full md:w-auto bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold py-2.5 px-6 rounded-xl transition-all">
                  {loadingAdvice ? "Analisando..." : "Pedir Mentoria"}
                </button>
              </div>
              {aiAdvice && (
                <div className={`p-6 rounded-2xl border-l-4 animate-in fade-in slide-in-from-bottom-2 ${aiAdvice.status === 'critical' ? 'bg-red-500/10 border-red-500' : 'bg-emerald-500/10 border-emerald-500'}`}>
                  <p className="text-base md:text-lg font-medium mb-4 italic text-slate-200 leading-relaxed">"{aiAdvice.message}"</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {aiAdvice.recommendations.map((rec, i) => (
                      <div key={i} className="flex items-start gap-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800">
                        <ChevronRightIcon className="w-4 h-4 text-emerald-400 flex-shrink-0 mt-0.5" />
                        <span className="text-sm text-slate-300">{rec}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-4 space-y-8">
          <div className="glass p-5 md:p-6 rounded-3xl sticky top-24">
            <div className="flex gap-2 p-1 bg-slate-900/50 rounded-xl mb-6">
               <button onClick={() => setFormType('expense')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'expense' ? 'bg-slate-800 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>GASTO</button>
               <button onClick={() => setFormType('fixed')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'fixed' ? 'bg-blue-500 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>FIXO</button>
               <button onClick={() => setFormType('income')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'income' ? 'bg-emerald-500 text-slate-950 shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>RENDA</button>
            </div>

            <form onSubmit={handleAddTransaction} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Descrição</label>
                <input type="text" placeholder="Ex: Café" value={description} onChange={(e) => setDescription(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Valor Total (MT)</label>
                <input type="number" placeholder="0.00" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold text-slate-100" />
              </div>

              {category === CategoryType.DEBT_INTEREST && formType === 'expense' && (
                <div className="space-y-1 animate-in slide-in-from-top-2 duration-200">
                  <label className="text-[10px] text-red-400 uppercase font-black ml-1">Valor dos Juros Inclusos (MT)</label>
                  <input type="number" placeholder="Opcional" value={interestAmount} onChange={(e) => setInterestAmount(e.target.value)} className="w-full bg-red-950/20 border border-red-900/50 rounded-xl px-4 py-3 focus:ring-2 focus:ring-red-500 outline-none transition-all font-bold text-red-400" />
                </div>
              )}

              {formType !== 'income' && (
                <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Categoria</label>
                  <div className="grid grid-cols-2 gap-2">
                    <button type="button" onClick={() => setCategory(CategoryType.NEED)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.NEED ? 'bg-blue-500/20 border-blue-500 text-blue-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Necessidade</button>
                    <button type="button" onClick={() => setCategory(CategoryType.WANT)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.WANT ? 'bg-purple-500/20 border-purple-500 text-purple-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Desejo</button>
                    {formType === 'expense' && (
                      <>
                        <button type="button" onClick={() => setCategory(CategoryType.SAVING)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.SAVING ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Reserva</button>
                        <button type="button" onClick={() => setCategory(CategoryType.DEBT_INTEREST)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.DEBT_INTEREST ? 'bg-red-500/20 border-red-500 text-red-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Dívida</button>
                      </>
                    )}
                  </div>
                </div>
              )}

              {formType !== 'fixed' && (
                <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Proveniência/Subcat</label>
                  <div className="relative">
                    <select value={subcategory} onChange={(e) => setSubcategory(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 outline-none text-sm appearance-none focus:ring-2 focus:ring-blue-500 transition-all cursor-pointer">
                      {SUBCATEGORIES[category].map((sub) => <option key={sub} value={sub}>{sub}</option>)}
                    </select>
                    <ChevronRightIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 rotate-90 pointer-events-none" />
                  </div>
                </div>
              )}

              <button type="submit" className={`w-full font-bold py-3.5 rounded-xl transition-all shadow-lg active:scale-[0.98] ${formType === 'income' ? 'bg-emerald-500 text-slate-950 hover:bg-emerald-400' : formType === 'fixed' ? 'bg-blue-500 text-white hover:bg-blue-400' : 'bg-white text-slate-950 hover:bg-slate-100'}`}>
                {formType === 'fixed' ? 'Salvar Gasto Fixo' : formType === 'income' ? 'Catalogar Renda' : 'Catalogar Gasto'}
              </button>
            </form>
          </div>

          <div className="glass p-5 md:p-6 rounded-3xl min-h-[400px]">
            <h3 className="text-sm font-bold mb-6 text-slate-400 uppercase tracking-widest flex items-center gap-2"><ClockIcon className="w-4 h-4" /> Atividade Recente</h3>
            <div className="space-y-3">
              {transactions.length === 0 ? (
                <div className="text-center py-20 text-slate-600 text-xs italic">Nenhum registro variável.</div>
              ) : (
                transactions.map((t) => {
                  const isInc = t.category === CategoryType.INCOME;
                  const isDebtWithInterest = t.category === CategoryType.DEBT_INTEREST && t.interestAmount && t.interestAmount > 0;
                  const interestPercentage = isDebtWithInterest ? ((t.interestAmount! / t.amount) * 100).toFixed(1) : '0';

                  return (
                    <div key={t.id} className={`group relative p-4 rounded-2xl border transition-all ${isInc ? 'bg-emerald-500/5 border-emerald-500/20' : isDebtWithInterest ? 'bg-red-500/10 border-red-500/30' : 'bg-slate-900/50 border-transparent hover:border-slate-800'}`}>
                      <div className={`absolute left-0 top-0 bottom-0 w-1 rounded-l-full ${isInc ? 'bg-emerald-500' : CATEGORY_COLORS[t.category]}`} />
                      <div className="flex justify-between items-start">
                        <div className="min-w-0 pr-2">
                          <p className="text-sm font-bold truncate flex items-center gap-2">
                            {t.description}
                            {isDebtWithInterest && <AlertTriangleIcon className="w-3 h-3 text-red-500" />}
                          </p>
                          <p className="text-[10px] text-slate-500 mt-1 flex items-center gap-1.5 truncate">
                             <TagIcon className="w-2.5 h-2.5" /> {t.subcategory} • {new Date(t.date).toLocaleDateString()}
                          </p>

                          {/* Alert for Debt Interest */}
                          {isDebtWithInterest && (
                            <div className="mt-2 p-2 bg-red-500/10 border border-red-500/20 rounded-lg flex items-start gap-2 animate-in fade-in duration-300">
                               <InfoIcon className="w-3 h-3 text-red-400 mt-0.5 flex-shrink-0" />
                               <p className="text-[9px] font-bold text-red-400 leading-tight">
                                 ALERTA DE JUROS: {formatCurrency(t.interestAmount!)} inclusos ({interestPercentage}% do montante). Esta dívida está a corroer o seu património.
                               </p>
                            </div>
                          )}
                        </div>
                        <div className="flex items-center gap-2 flex-shrink-0">
                           <span className={`font-black text-sm whitespace-nowrap ${isInc ? 'text-emerald-400' : 'text-slate-100'}`}>{isInc ? '+' : '-'}{formatCurrency(t.amount)}</span>
                           <button onClick={() => { setTransactionToDelete(t.id); setShowDeleteModal(true); }} className="p-1.5 text-slate-600 hover:text-red-400 transition-all"><Trash2Icon className="w-4 h-4" /></button>
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>
      </main>

      {showDeleteModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowDeleteModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6 animate-in zoom-in duration-200">
            <h3 className="text-xl font-bold text-center">Apagar Registro?</h3>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowDeleteModal(false)} className="py-3 rounded-xl bg-slate-800 text-slate-300 font-bold">Voltar</button>
              <button onClick={executeDelete} className="py-3 rounded-xl bg-red-600 text-white font-bold">Apagar</button>
            </div>
          </div>
        </div>
      )}

      {showResetModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowResetModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6 animate-in zoom-in duration-200 text-center">
            <h3 className="text-xl font-bold">Recomeçar Tudo?</h3>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowResetModal(false)} className="py-3 rounded-xl bg-slate-800 font-bold">Cancelar</button>
              <button onClick={handleResetData} className="py-3 rounded-xl bg-orange-600 font-bold">Sim, Reset</button>
            </div>
          </div>
        </div>
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-950/90 backdrop-blur-md border-t border-slate-900 py-3 px-4 flex justify-center items-center text-[9px] md:text-[10px] tracking-[0.2em] text-slate-600 uppercase text-center">
        Finmo • {new Date().getFullYear()}
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PlusIcon, 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon,
  TagIcon,
  AlertTriangleIcon,
  XIcon,
  RotateCcwIcon,
  CalendarIcon,
  ArrowRightIcon,
  FlameIcon,
  HandCoinsIcon,
  ClockIcon,
  ArrowDownLeftIcon,
  ArrowUpRightIcon,
  BanknoteIcon,
  RepeatIcon,
  Settings2Icon,
  InfoIcon,
  LineChartIcon,
  CalendarDaysIcon
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell,
  PieChart,
  Pie,
  AreaChart,
  Area
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice, FixedExpense } from './types';
import { CURRENCY, CATEGORY_LABELS, CATEGORY_COLORS, SUBCATEGORIES, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

const App: React.FC = () => {
  // Persistence states
  const [baseIncome, setBaseIncome] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_income');
    return saved ? Number(saved) : 30000;
  });

  const [payday, setPayday] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_payday');
    return saved ? Number(saved) : 1;
  });

  const [fixedExpenses, setFixedExpenses] = useState<FixedExpense[]>(() => {
    const saved = localStorage.getItem('finmo_fixed');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finmo_transactions');
    try {
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Erro ao carregar transações:", e);
      return [];
    }
  });

  // UI / Form states
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [interestAmount, setInterestAmount] = useState('');
  const [formType, setFormType] = useState<'expense' | 'income' | 'fixed'>('expense');
  const [category, setCategory] = useState<CategoryType>(CategoryType.NEED);
  const [subcategory, setSubcategory] = useState<string>(SUBCATEGORIES[CategoryType.NEED][0]);
  const [dueDate, setDueDate] = useState('');
  const [aiAdvice, setAiAdvice] = useState<AIAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [showFixedManager, setShowFixedManager] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [transactionToDelete, setTransactionToDelete] = useState<string | null>(null);
  const [showResetModal, setShowResetModal] = useState(false);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('finmo_income', baseIncome.toString()), [baseIncome]);
  useEffect(() => localStorage.setItem('finmo_payday', payday.toString()), [payday]);
  useEffect(() => localStorage.setItem('finmo_fixed', JSON.stringify(fixedExpenses)), [fixedExpenses]);
  useEffect(() => localStorage.setItem('finmo_transactions', JSON.stringify(transactions)), [transactions]);

  // Adjust category based on form type
  useEffect(() => {
    if (formType === 'income') setCategory(CategoryType.INCOME);
    else if (formType === 'fixed') setCategory(CategoryType.NEED);
    else if (category === CategoryType.INCOME) setCategory(CategoryType.NEED);
  }, [formType]);

  useEffect(() => {
    setSubcategory(SUBCATEGORIES[category][0]);
    if (category !== CategoryType.DEBT_INTEREST && category !== CategoryType.DEBT_NO_INTEREST) {
      setDueDate('');
      setInterestAmount('');
    }
  }, [category]);

  const stats = useMemo<BudgetStats>(() => {
    const s: BudgetStats = { 
      baseIncome, 
      variableIncome: 0, 
      totalIncome: 0,
      fixedNeeds: 0,
      variableNeeds: 0,
      totalNeeds: 0,
      wants: 0,
      fixedWants: 0,
      savings: 0, 
      debtInterest: 0, 
      debtNoInterest: 0, 
      fixedDebts: 0,
      totalSpent: 0 
    };

    fixedExpenses.forEach(fe => {
      if (fe.category === CategoryType.NEED) s.fixedNeeds += fe.amount;
      if (fe.category === CategoryType.WANT) s.fixedWants += fe.amount;
      if (fe.category === CategoryType.DEBT_NO_INTEREST) s.fixedDebts += fe.amount;
    });

    transactions.forEach(t => {
      if (t.category === CategoryType.INCOME) {
        s.variableIncome += t.amount;
      } else {
        if (t.category === CategoryType.NEED) s.variableNeeds += t.amount;
        if (t.category === CategoryType.WANT) s.wants += t.amount;
        if (t.category === CategoryType.SAVING) s.savings += t.amount;
        if (t.category === CategoryType.DEBT_INTEREST) s.debtInterest += t.amount;
        if (t.category === CategoryType.DEBT_NO_INTEREST) s.debtNoInterest += t.amount;
      }
    });

    s.totalIncome = s.baseIncome + s.variableIncome;
    s.totalNeeds = s.fixedNeeds + s.variableNeeds;
    s.totalSpent = s.totalNeeds + s.wants + s.fixedWants + s.savings + s.debtInterest + s.debtNoInterest + s.fixedDebts;

    return s;
  }, [transactions, baseIncome, fixedExpenses]);

  // Cash Flow Projection Logic
  const projectionData = useMemo(() => {
    const days = 30;
    const data = [];
    let currentBalance = stats.totalIncome - stats.totalSpent;
    const totalFixedPerMonth = stats.fixedNeeds + stats.fixedWants + stats.fixedDebts;

    const today = new Date();

    for (let i = 0; i <= days; i++) {
      const date = new Date(today);
      date.setDate(today.getDate() + i);
      const dayOfMonth = date.getDate();

      // Simulate payday
      if (dayOfMonth === payday && i > 0) {
        currentBalance += baseIncome;
        // On payday, we assume fixed expenses are renewed/debited for the new cycle
        currentBalance -= totalFixedPerMonth;
      }

      data.push({
        day: date.toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' }),
        balance: Math.max(0, currentBalance),
        rawBalance: currentBalance
      });

      // Simple model: assume remaining variable budget is spent linearly 
      // This is for visual projection purposes
      const remainingDaysInMonth = 30 - dayOfMonth; // simplified
      // We don't deduct daily variable spending in projection to show "potential" balance
    }
    return data;
  }, [stats, payday, baseIncome]);

  const targets = {
    [CategoryType.NEED]: stats.totalIncome * 0.5,
    [CategoryType.WANT]: stats.totalIncome * 0.3,
    [CategoryType.SAVING]: stats.totalIncome * 0.2,
  };

  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    const val = parseFloat(amount);

    if (formType === 'fixed') {
      const newFixed: FixedExpense = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        category: category as any
      };
      setFixedExpenses([...fixedExpenses, newFixed]);
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        interestAmount: interestAmount ? parseFloat(interestAmount) : undefined,
        category,
        subcategory,
        date: new Date().toISOString(),
        dueDate: isDebt(category) ? dueDate : undefined
      };
      setTransactions([newTransaction, ...transactions]);
    }

    setDescription('');
    setAmount('');
    setInterestAmount('');
    setDueDate('');
  };

  const executeDelete = () => {
    if (transactionToDelete) {
      setTransactions(transactions.filter(t => t.id !== transactionToDelete));
      setTransactionToDelete(null);
      setShowDeleteModal(false);
    }
  };

  const handleResetData = () => {
    setBaseIncome(30000);
    setPayday(1);
    setFixedExpenses([]);
    setTransactions([]);
    setAiAdvice(null);
    setShowResetModal(false);
  };

  const removeFixed = (id: string) => {
    setFixedExpenses(fixedExpenses.filter(fe => fe.id !== id));
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, stats.totalIncome);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  const isDebt = (cat: CategoryType) => cat === CategoryType.DEBT_INTEREST || cat === CategoryType.DEBT_NO_INTEREST;

  // Calculate safe to spend daily
  const daysUntilPayday = useMemo(() => {
    const today = new Date();
    const currentDay = today.getDate();
    if (currentDay < payday) return payday - currentDay;
    const lastDayOfMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();
    return (lastDayOfMonth - currentDay) + payday;
  }, [payday]);

  const safeToSpendDaily = useMemo(() => {
    const currentBalance = stats.totalIncome - stats.totalSpent;
    return Math.max(0, currentBalance / (daysUntilPayday || 1));
  }, [stats, daysUntilPayday]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 glass border-b border-slate-800 px-4 md:px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-500 p-2 rounded-xl shadow-lg shadow-emerald-500/20">
            <WalletIcon className="w-5 h-5 md:w-6 md:h-6 text-slate-900" />
          </div>
          <h1 className="text-xl md:text-2xl font-bold tracking-tight">Finmo</h1>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
          <button 
            onClick={() => setShowFixedManager(!showFixedManager)}
            className={`p-2 rounded-lg transition-all flex items-center gap-2 text-[10px] md:text-xs font-bold uppercase tracking-widest ${showFixedManager ? 'bg-blue-500 text-white' : 'text-slate-500 hover:text-blue-400'}`}
          >
            <RepeatIcon className="w-4 h-4" />
            <span className="hidden sm:inline">Gastos Fixos</span>
          </button>

          <button 
            onClick={() => setShowSettings(true)}
            className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg text-slate-300 transition-all flex items-center gap-2"
          >
            <Settings2Icon className="w-4 h-4 md:w-5 md:h-5" />
            <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Ajustes</span>
          </button>

          <button onClick={() => setShowResetModal(true)} className="p-2 text-slate-500 hover:text-red-400 transition-colors">
            <RotateCcwIcon className="w-5 h-5" />
          </button>
        </div>
      </header>

      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-sm" onClick={() => setShowSettings(false)} />
          <div className="relative glass p-6 md:p-8 rounded-3xl max-w-sm w-full space-y-6 shadow-2xl border-slate-700 animate-in zoom-in duration-200">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold flex items-center gap-2">
                <Settings2Icon className="w-5 h-5 text-emerald-400" />
                Configuração Base
              </h3>
              <button onClick={() => setShowSettings(false)} className="p-1 hover:bg-slate-800 rounded-lg transition-colors">
                <XIcon className="w-5 h-5 text-slate-500" />
              </button>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Renda Fixa Mensal (Base)</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-500 font-bold text-xs">MT</span>
                  <input 
                    type="number" 
                    value={baseIncome} 
                    onChange={(e) => setBaseIncome(Number(e.target.value))} 
                    className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-400 font-bold" 
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Dia do Salário</label>
                <div className="relative">
                  <CalendarIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                  <input 
                    type="number" 
                    min="1" 
                    max="31"
                    value={payday} 
                    onChange={(e) => setPayday(Number(e.target.value))} 
                    className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none text-slate-200 font-bold" 
                  />
                </div>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold py-3 rounded-xl transition-all shadow-lg">Confirmar Ajustes</button>
          </div>
        </div>
      )}

      <main className="max-w-6xl mx-auto p-4 lg:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-8 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {[
              { label: 'Essenciais*', val: stats.totalNeeds + stats.debtInterest + stats.debtNoInterest + stats.fixedDebts, fixed: stats.fixedNeeds + stats.fixedDebts, target: targets[CategoryType.NEED], color: 'blue', icon: CreditCardIcon },
              { label: 'Desejos', val: stats.wants + stats.fixedWants, fixed: stats.fixedWants, target: targets[CategoryType.WANT], color: 'purple', icon: PieChartIcon },
              { label: 'Reserva', val: stats.savings, fixed: 0, target: targets[CategoryType.SAVING], color: 'emerald', icon: TrendingUpIcon }
            ].map((card, idx) => {
              const isOver = card.val > card.target;
              return (
                <div key={idx} className={`glass p-6 rounded-3xl space-y-2 border-l-4 transition-all ${isOver ? 'border-red-500 shadow-lg shadow-red-900/10' : `border-${card.color}-500`}`}>
                  <div className="flex justify-between items-start">
                    <p className="text-slate-400 text-sm">{card.label}</p>
                    <card.icon className={`w-4 h-4 ${isOver ? 'text-red-500' : `text-${card.color}-500`}`} />
                  </div>
                  <p className={`text-xl font-bold ${isOver ? 'text-red-400' : ''}`}>{formatCurrency(card.val)}</p>
                  <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden flex">
                    <div className="bg-slate-500 h-full opacity-50" style={{ width: `${Math.min(100, (card.fixed / (card.target || 1)) * 100)}%` }} />
                    <div className={`${isOver ? 'bg-red-500' : `bg-${card.color}-500`} h-full`} style={{ width: `${Math.min(100, ((card.val - card.fixed) / (card.target || 1)) * 100)}%` }} />
                  </div>
                  <div className="flex justify-between text-[9px] text-slate-500 uppercase font-bold">
                    <span>Meta: {formatCurrency(card.target)}</span>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Cash Flow Projection Section */}
          <div className="glass p-6 md:p-8 rounded-3xl space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
              <div className="flex items-center gap-3">
                <div className="bg-blue-500/20 p-3 rounded-2xl"><LineChartIcon className="w-6 h-6 text-blue-400" /></div>
                <div>
                  <h2 className="text-xl font-bold">Previsão de Fluxo de Caixa</h2>
                  <p className="text-xs text-slate-500">Projeção para os próximos 30 dias</p>
                </div>
              </div>
              <div className="bg-slate-900/80 px-4 py-2 rounded-xl border border-slate-800 flex items-center gap-4">
                 <div className="text-center">
                    <p className="text-[9px] text-slate-500 uppercase font-black">Gasto Diário Seguro</p>
                    <p className="text-sm font-black text-emerald-400">{formatCurrency(safeToSpendDaily)}</p>
                 </div>
                 <div className="w-px h-8 bg-slate-800" />
                 <div className="text-center">
                    <p className="text-[9px] text-slate-500 uppercase font-black">Próximo Salário em</p>
                    <p className="text-sm font-black text-blue-400">{daysUntilPayday} dias</p>
                 </div>
              </div>
            </div>

            <div className="h-[250px] w-full mt-4">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={projectionData}>
                  <defs>
                    <linearGradient id="colorBalance" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                      <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                  <XAxis 
                    dataKey="day" 
                    stroke="#475569" 
                    fontSize={10} 
                    tickLine={false} 
                    axisLine={false}
                    interval={5}
                  />
                  <YAxis 
                    stroke="#475569" 
                    fontSize={10} 
                    tickLine={false} 
                    axisLine={false}
                    tickFormatter={(value) => `${value / 1000}k`}
                  />
                  <Tooltip 
                    contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px', fontSize: '12px' }}
                    itemStyle={{ color: '#3b82f6', fontWeight: 'bold' }}
                    formatter={(value: number) => [formatCurrency(value), 'Saldo Projetado']}
                  />
                  <Area 
                    type="monotone" 
                    dataKey="balance" 
                    stroke="#3b82f6" 
                    strokeWidth={3}
                    fillOpacity={1} 
                    fill="url(#colorBalance)" 
                  />
                </AreaChart>
              </ResponsiveContainer>
            </div>

            <div className="flex items-start gap-3 bg-blue-500/5 p-4 rounded-2xl border border-blue-500/10">
              <InfoIcon className="w-5 h-5 text-blue-400 flex-shrink-0 mt-0.5" />
              <p className="text-xs text-slate-400 leading-relaxed">
                Esta projeção considera que o seu saldo atual será reforçado no dia <span className="text-blue-400 font-bold">{payday}</span> com a sua renda base de <span className="text-blue-400 font-bold">{formatCurrency(baseIncome)}</span>, após deduzir os gastos fixos mensais. Utilize o "Gasto Diário Seguro" para garantir que chega ao fim do ciclo com saldo positivo.
              </p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="glass p-5 rounded-3xl border-l-4 border-emerald-500 bg-emerald-500/5 flex justify-between items-center group">
              <div>
                <p className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest">Disponível p/ Gasto Livre</p>
                <p className="text-2xl font-black">{formatCurrency(stats.totalIncome - (stats.fixedNeeds + stats.fixedWants + stats.fixedDebts))}</p>
              </div>
              <BanknoteIcon className="w-8 h-8 text-emerald-500/20" />
            </div>
            <div className="glass p-5 rounded-3xl border-l-4 border-red-500 bg-red-500/5 flex justify-between items-center">
              <div>
                <p className="text-[10px] text-red-400 font-bold uppercase tracking-widest">Compromissos Fixos (Mês)</p>
                <p className="text-2xl font-black">{formatCurrency(stats.fixedNeeds + stats.fixedWants + stats.fixedDebts)}</p>
              </div>
              <FlameIcon className="w-8 h-8 text-red-500/20" />
            </div>
          </div>

          <div className="relative overflow-hidden group">
            <div className="absolute -inset-1 bg-gradient-to-r from-emerald-500 to-blue-500 rounded-3xl blur opacity-25"></div>
            <div className="relative glass p-6 md:p-8 rounded-3xl space-y-6">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div className="flex items-center gap-3">
                  <div className="bg-emerald-500/20 p-3 rounded-2xl"><SparklesIcon className="w-6 h-6 text-emerald-400" /></div>
                  <div>
                    <h2 className="text-xl font-bold">Mentor Finmo</h2>
                    <p className="text-xs text-slate-500">Inteligência pragmática em tempo real</p>
                  </div>
                </div>
                <button onClick={getMentorship} disabled={loadingAdvice} className="w-full md:w-auto bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold py-2.5 px-6 rounded-xl transition-all">
                  {loadingAdvice ? "Analisando..." : "Pedir Mentoria"}
                </button>
              </div>
              {aiAdvice && (
                <div className={`p-6 rounded-2xl border-l-4 animate-in fade-in slide-in-from-bottom-2 ${aiAdvice.status === 'critical' ? 'bg-red-500/10 border-red-500' : 'bg-emerald-500/10 border-emerald-500'}`}>
                  <p className="text-base md:text-lg font-medium mb-4 italic text-slate-200 leading-relaxed">"{aiAdvice.message}"</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {aiAdvice.recommendations.map((rec, i) => (
                      <div key={i} className="flex items-start gap-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800">
                        <ChevronRightIcon className="w-4 h-4 text-emerald-400 flex-shrink-0 mt-0.5" />
                        <span className="text-sm text-slate-300">{rec}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-4 space-y-8">
          <div className="glass p-5 md:p-6 rounded-3xl sticky top-24">
            <div className="flex gap-2 p-1 bg-slate-900/50 rounded-xl mb-6">
               <button onClick={() => setFormType('expense')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'expense' ? 'bg-slate-800 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>GASTO</button>
               <button onClick={() => setFormType('fixed')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'fixed' ? 'bg-blue-500 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>FIXO</button>
               <button onClick={() => setFormType('income')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'income' ? 'bg-emerald-500 text-slate-950 shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>RENDA</button>
            </div>

            <form onSubmit={handleAddTransaction} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Descrição</label>
                <input type="text" placeholder="Ex: Café" value={description} onChange={(e) => setDescription(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Valor Total (MT)</label>
                <input type="number" placeholder="0.00" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold text-slate-100" />
              </div>

              {category === CategoryType.DEBT_INTEREST && formType === 'expense' && (
                <div className="space-y-1 animate-in slide-in-from-top-2 duration-200">
                  <label className="text-[10px] text-red-400 uppercase font-black ml-1">Valor dos Juros Inclusos (MT)</label>
                  <input type="number" placeholder="Opcional" value={interestAmount} onChange={(e) => setInterestAmount(e.target.value)} className="w-full bg-red-950/20 border border-red-900/50 rounded-xl px-4 py-3 focus:ring-2 focus:ring-red-500 outline-none transition-all font-bold text-red-400" />
                </div>
              )}

              {formType !== 'income' && (
                <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Categoria</label>
                  <div className="grid grid-cols-2 gap-2">
                    <button type="button" onClick={() => setCategory(CategoryType.NEED)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.NEED ? 'bg-blue-500/20 border-blue-500 text-blue-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Necessidade</button>
                    <button type="button" onClick={() => setCategory(CategoryType.WANT)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.WANT ? 'bg-purple-500/20 border-purple-500 text-purple-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Desejo</button>
                    {formType === 'expense' && (
                      <>
                        <button type="button" onClick={() => setCategory(CategoryType.SAVING)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.SAVING ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Reserva</button>
                        <button type="button" onClick={() => setCategory(CategoryType.DEBT_INTEREST)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.DEBT_INTEREST ? 'bg-red-500/20 border-red-500 text-red-400 font-bold shadow-sm' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Dívida</button>
                      </>
                    )}
                  </div>
                </div>
              )}

              {formType !== 'fixed' && (
                <div className="space-y-1">
                  <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Proveniência/Subcat</label>
                  <div className="relative">
                    <select value={subcategory} onChange={(e) => setSubcategory(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 outline-none text-sm appearance-none focus:ring-2 focus:ring-blue-500 transition-all cursor-pointer">
                      {SUBCATEGORIES[category].map((sub) => <option key={sub} value={sub}>{sub}</option>)}
                    </select>
                    <ChevronRightIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 rotate-90 pointer-events-none" />
                  </div>
                </div>
              )}

              <button type="submit" className={`w-full font-bold py-3.5 rounded-xl transition-all shadow-lg active:scale-[0.98] ${formType === 'income' ? 'bg-emerald-500 text-slate-950 hover:bg-emerald-400' : formType === 'fixed' ? 'bg-blue-500 text-white hover:bg-blue-400' : 'bg-white text-slate-950 hover:bg-slate-100'}`}>
                {formType === 'fixed' ? 'Salvar Gasto Fixo' : formType === 'income' ? 'Catalogar Renda' : 'Catalogar Gasto'}
              </button>
            </form>
          </div>

          <div className="glass p-5 md:p-6 rounded-3xl min-h-[400px]">
            <h3 className="text-sm font-bold mb-6 text-slate-400 uppercase tracking-widest flex items-center gap-2"><ClockIcon className="w-4 h-4" /> Atividade Recente</h3>
            <div className="space-y-3">
              {transactions.length === 0 ? (
                <div className="text-center py-20 text-slate-600 text-xs italic">Nenhum registro variável.</div>
              ) : (
                transactions.map((t) => {
                  const isInc = t.category === CategoryType.INCOME;
                  const isDebtWithInterest = t.category === CategoryType.DEBT_INTEREST && t.interestAmount && t.interestAmount > 0;
                  const interestPercentage = isDebtWithInterest ? ((t.interestAmount! / t.amount) * 100).toFixed(1) : '0';

                  return (
                    <div key={t.id} className={`group relative p-4 rounded-2xl border transition-all ${isInc ? 'bg-emerald-500/5 border-emerald-500/20' : isDebtWithInterest ? 'bg-red-500/10 border-red-500/30' : 'bg-slate-900/50 border-transparent hover:border-slate-800'}`}>
                      <div className={`absolute left-0 top-0 bottom-0 w-1 rounded-l-full ${isInc ? 'bg-emerald-500' : CATEGORY_COLORS[t.category]}`} />
                      <div className="flex justify-between items-start">
                        <div className="min-w-0 pr-2">
                          <p className="text-sm font-bold truncate flex items-center gap-2">
                            {t.description}
                            {isDebtWithInterest && <AlertTriangleIcon className="w-3 h-3 text-red-500" />}
                          </p>
                          <p className="text-[10px] text-slate-500 mt-1 flex items-center gap-1.5 truncate">
                             <TagIcon className="w-2.5 h-2.5" /> {t.subcategory} • {new Date(t.date).toLocaleDateString()}
                          </p>

                          {/* Alert for Debt Interest */}
                          {isDebtWithInterest && (
                            <div className="mt-2 p-2 bg-red-500/10 border border-red-500/20 rounded-lg flex items-start gap-2 animate-in fade-in duration-300">
                               <InfoIcon className="w-3 h-3 text-red-400 mt-0.5 flex-shrink-0" />
                               <p className="text-[9px] font-bold text-red-400 leading-tight">
                                 ALERTA DE JUROS: {formatCurrency(t.interestAmount!)} inclusos ({interestPercentage}% do montante). Esta dívida está a corroer o seu património.
                               </p>
                            </div>
                          )}
                        </div>
                        <div className="flex items-center gap-2 flex-shrink-0">
                           <span className={`font-black text-sm whitespace-nowrap ${isInc ? 'text-emerald-400' : 'text-slate-100'}`}>{isInc ? '+' : '-'}{formatCurrency(t.amount)}</span>
                           <button onClick={() => { setTransactionToDelete(t.id); setShowDeleteModal(true); }} className="p-1.5 text-slate-600 hover:text-red-400 transition-all"><Trash2Icon className="w-4 h-4" /></button>
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>
      </main>

      {showDeleteModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowDeleteModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6 animate-in zoom-in duration-200">
            <h3 className="text-xl font-bold text-center">Apagar Registro?</h3>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowDeleteModal(false)} className="py-3 rounded-xl bg-slate-800 text-slate-300 font-bold">Voltar</button>
              <button onClick={executeDelete} className="py-3 rounded-xl bg-red-600 text-white font-bold">Apagar</button>
            </div>
          </div>
        </div>
      )}

      {showResetModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowResetModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6 animate-in zoom-in duration-200 text-center">
            <h3 className="text-xl font-bold">Recomeçar Tudo?</h3>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowResetModal(false)} className="py-3 rounded-xl bg-slate-800 font-bold">Cancelar</button>
              <button onClick={handleResetData} className="py-3 rounded-xl bg-orange-600 font-bold">Sim, Reset</button>
            </div>
          </div>
        </div>
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-950/90 backdrop-blur-md border-t border-slate-900 py-3 px-4 flex justify-center items-center text-[9px] md:text-[10px] tracking-[0.2em] text-slate-600 uppercase text-center">
        Finmo • {new Date().getFullYear()}
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon,
  TagIcon,
  AlertTriangleIcon,
  XIcon,
  RotateCcwIcon,
  CalendarIcon,
  ArrowRightIcon,
  FlameIcon,
  BanknoteIcon,
  RepeatIcon,
  Settings2Icon,
  InfoIcon,
  LineChartIcon,
  ClockIcon,
  LogOutIcon,
  CloudCheckIcon,
  CloudIcon
} from 'lucide-react';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  AreaChart,
  Area
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice, FixedExpense } from './types';
import { CATEGORY_LABELS, CATEGORY_COLORS, SUBCATEGORIES, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

interface User {
  name: string;
  email: string;
  picture: string;
}

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('finmo_user');
    return saved ? JSON.parse(saved) : null;
  });

  // Persistence states
  const [baseIncome, setBaseIncome] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_income');
    return saved ? Number(saved) : 30000;
  });

  const [payday, setPayday] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_payday');
    return saved ? Number(saved) : 1;
  });

  const [fixedExpenses, setFixedExpenses] = useState<FixedExpense[]>(() => {
    const saved = localStorage.getItem('finmo_fixed');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finmo_transactions');
    try {
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Erro ao carregar transações:", e);
      return [];
    }
  });

  // UI / Form states
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [interestAmount, setInterestAmount] = useState('');
  const [formType, setFormType] = useState<'expense' | 'income' | 'fixed'>('expense');
  const [category, setCategory] = useState<CategoryType>(CategoryType.NEED);
  const [subcategory, setSubcategory] = useState<string>(SUBCATEGORIES[CategoryType.NEED][0]);
  const [dueDate, setDueDate] = useState('');
  const [aiAdvice, setAiAdvice] = useState<AIAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [showFixedManager, setShowFixedManager] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [transactionToDelete, setTransactionToDelete] = useState<string | null>(null);
  const [showResetModal, setShowResetModal] = useState(false);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('finmo_income', baseIncome.toString()), [baseIncome]);
  useEffect(() => localStorage.setItem('finmo_payday', payday.toString()), [payday]);
  useEffect(() => localStorage.setItem('finmo_fixed', JSON.stringify(fixedExpenses)), [fixedExpenses]);
  useEffect(() => localStorage.setItem('finmo_transactions', JSON.stringify(transactions)), [transactions]);
  useEffect(() => {
    if (user) localStorage.setItem('finmo_user', JSON.stringify(user));
    else localStorage.removeItem('finmo_user');
  }, [user]);

  // Google Auth Initialization
  useEffect(() => {
    const handleCredentialResponse = (response: any) => {
      try {
        const payload = JSON.parse(atob(response.credential.split('.')[1]));
        const userData: User = {
          name: payload.name,
          email: payload.email,
          picture: payload.picture
        };
        setUser(userData);
      } catch (error) {
        console.error("Erro ao decodificar token do Google", error);
      }
    };

    if (window.google) {
      window.google.accounts.id.initialize({
        client_id: "YOUR_GOOGLE_CLIENT_ID.apps.googleusercontent.com", // Em produção o usuário forneceria isso
        callback: handleCredentialResponse,
        auto_select: false
      });

      if (!user) {
        window.google.accounts.id.renderButton(
          document.getElementById("google-login-btn"),
          { theme: "outline", size: "medium", type: "standard", shape: "pill", text: "signin_with", logo_alignment: "left" }
        );
      }
    }
  }, [user]);

  const handleLogout = () => {
    setUser(null);
    window.location.reload(); // Recarregar para resetar instâncias se necessário
  };

  // Adjust category based on form type
  useEffect(() => {
    if (formType === 'income') setCategory(CategoryType.INCOME);
    else if (formType === 'fixed') setCategory(CategoryType.NEED);
    else if (category === CategoryType.INCOME) setCategory(CategoryType.NEED);
  }, [formType]);

  useEffect(() => {
    setSubcategory(SUBCATEGORIES[category][0]);
    if (category !== CategoryType.DEBT_INTEREST && category !== CategoryType.DEBT_NO_INTEREST) {
      setDueDate('');
      setInterestAmount('');
    }
  }, [category]);

  const stats = useMemo<BudgetStats>(() => {
    const s: BudgetStats = { 
      baseIncome, 
      variableIncome: 0, 
      totalIncome: 0,
      fixedNeeds: 0,
      variableNeeds: 0,
      totalNeeds: 0,
      wants: 0,
      fixedWants: 0,
      savings: 0, 
      debtInterest: 0, 
      debtNoInterest: 0, 
      fixedDebts: 0,
      totalSpent: 0 
    };

    fixedExpenses.forEach(fe => {
      if (fe.category === CategoryType.NEED) s.fixedNeeds += fe.amount;
      if (fe.category === CategoryType.WANT) s.fixedWants += fe.amount;
      if (fe.category === CategoryType.DEBT_NO_INTEREST) s.fixedDebts += fe.amount;
    });

    transactions.forEach(t => {
      if (t.category === CategoryType.INCOME) {
        s.variableIncome += t.amount;
      } else {
        if (t.category === CategoryType.NEED) s.variableNeeds += t.amount;
        if (t.category === CategoryType.WANT) s.wants += t.amount;
        if (t.category === CategoryType.SAVING) s.savings += t.amount;
        if (t.category === CategoryType.DEBT_INTEREST) s.debtInterest += t.amount;
        if (t.category === CategoryType.DEBT_NO_INTEREST) s.debtNoInterest += t.amount;
      }
    });

    s.totalIncome = s.baseIncome + s.variableIncome;
    s.totalNeeds = s.fixedNeeds + s.variableNeeds;
    s.totalSpent = s.totalNeeds + s.wants + s.fixedWants + s.savings + s.debtInterest + s.debtNoInterest + s.fixedDebts;

    return s;
  }, [transactions, baseIncome, fixedExpenses]);

  // Cash Flow Projection
  const projectionData = useMemo(() => {
    const days = 30;
    const data = [];
    let currentBalance = stats.totalIncome - stats.totalSpent;
    const totalFixedPerMonth = stats.fixedNeeds + stats.fixedWants + stats.fixedDebts;
    const today = new Date();

    for (let i = 0; i <= days; i++) {
      const date = new Date(today);
      date.setDate(today.getDate() + i);
      const dayOfMonth = date.getDate();
      if (dayOfMonth === payday && i > 0) {
        currentBalance += baseIncome;
        currentBalance -= totalFixedPerMonth;
      }
      data.push({
        day: date.toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' }),
        balance: Math.max(0, currentBalance),
      });
    }
    return data;
  }, [stats, payday, baseIncome]);

  const targets = {
    [CategoryType.NEED]: stats.totalIncome * 0.5,
    [CategoryType.WANT]: stats.totalIncome * 0.3,
    [CategoryType.SAVING]: stats.totalIncome * 0.2,
  };

  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;
    const val = parseFloat(amount);

    if (formType === 'fixed') {
      const newFixed: FixedExpense = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        category: category as any
      };
      setFixedExpenses([...fixedExpenses, newFixed]);
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        interestAmount: interestAmount ? parseFloat(interestAmount) : undefined,
        category,
        subcategory,
        date: new Date().toISOString(),
        dueDate: isDebt(category) ? dueDate : undefined
      };
      setTransactions([newTransaction, ...transactions]);
    }

    setDescription('');
    setAmount('');
    setInterestAmount('');
    setDueDate('');
  };

  const executeDelete = () => {
    if (transactionToDelete) {
      setTransactions(transactions.filter(t => t.id !== transactionToDelete));
      setTransactionToDelete(null);
      setShowDeleteModal(false);
    }
  };

  const handleResetData = () => {
    setBaseIncome(30000);
    setPayday(1);
    setFixedExpenses([]);
    setTransactions([]);
    setAiAdvice(null);
    setShowResetModal(false);
  };

  const removeFixed = (id: string) => {
    setFixedExpenses(fixedExpenses.filter(fe => fe.id !== id));
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, stats.totalIncome);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  const isDebt = (cat: CategoryType) => cat === CategoryType.DEBT_INTEREST || cat === CategoryType.DEBT_NO_INTEREST;

  const daysUntilPayday = useMemo(() => {
    const today = new Date();
    const currentDay = today.getDate();
    if (currentDay < payday) return payday - currentDay;
    const lastDayOfMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();
    return (lastDayOfMonth - currentDay) + payday;
  }, [payday]);

  const safeToSpendDaily = useMemo(() => {
    const currentBalance = stats.totalIncome - stats.totalSpent;
    return Math.max(0, currentBalance / (daysUntilPayday || 1));
  }, [stats, daysUntilPayday]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 glass border-b border-slate-800 px-4 md:px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="bg-emerald-500 p-2 rounded-xl shadow-lg shadow-emerald-500/20">
            <WalletIcon className="w-5 h-5 md:w-6 md:h-6 text-slate-900" />
          </div>
          <div>
            <h1 className="text-xl md:text-2xl font-bold tracking-tight">Finmo</h1>
            {user && (
              <div className="flex items-center gap-1 mt-0.5">
                <CloudIcon className="w-2.5 h-2.5 text-emerald-500" />
                <span className="text-[8px] uppercase tracking-widest text-emerald-500 font-bold">Cloud Sync Ativo</span>
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
          <button 
            onClick={() => setShowFixedManager(!showFixedManager)}
            className={`p-2 rounded-lg transition-all flex items-center gap-2 text-[10px] md:text-xs font-bold uppercase tracking-widest ${showFixedManager ? 'bg-blue-500 text-white' : 'text-slate-500 hover:text-blue-400'}`}
          >
            <RepeatIcon className="w-4 h-4" />
            <span className="hidden sm:inline">Fixos</span>
          </button>

          <button 
            onClick={() => setShowSettings(true)}
            className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg text-slate-300 transition-all flex items-center gap-2"
          >
            <Settings2Icon className="w-4 h-4" />
            <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Ajustes</span>
          </button>

          <div className="w-px h-6 bg-slate-800 mx-1 hidden sm:block" />

          {user ? (
            <div className="flex items-center gap-3 pl-2 border-l border-slate-800">
               <div className="text-right hidden sm:block">
                 <p className="text-[10px] font-bold truncate max-w-[100px]">{user.name}</p>
                 <button onClick={handleLogout} className="text-[9px] text-slate-500 hover:text-red-400 uppercase tracking-tighter">Sair</button>
               </div>
               <img src={user.picture} alt={user.name} className="w-8 h-8 rounded-full border border-emerald-500/50 shadow-lg shadow-emerald-500/10" />
            </div>
          ) : (
            <div id="google-login-btn" className="scale-90 md:scale-100 origin-right"></div>
          )}
        </div>
      </header>

      {showSettings && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-sm" onClick={() => setShowSettings(false)} />
          <div className="relative glass p-6 md:p-8 rounded-3xl max-w-sm w-full space-y-6 shadow-2xl border-slate-700 animate-in zoom-in duration-200">
            <div className="flex justify-between items-center">
              <h3 className="text-lg font-bold flex items-center gap-2">
                <Settings2Icon className="w-5 h-5 text-emerald-400" />
                Configuração Base
              </h3>
              <button onClick={() => setShowSettings(false)} className="p-1 hover:bg-slate-800 rounded-lg transition-colors">
                <XIcon className="w-5 h-5 text-slate-500" />
              </button>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Renda Fixa Mensal (Base)</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-500 font-bold text-xs">MT</span>
                  <input type="number" value={baseIncome} onChange={(e) => setBaseIncome(Number(e.target.value))} className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-400 font-bold" />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] text-slate-500 uppercase font-black ml-1">Dia do Salário</label>
                <div className="relative">
                  <CalendarIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                  <input type="number" min="1" max="31" value={payday} onChange={(e) => setPayday(Number(e.target.value))} className="w-full bg-slate-900 border border-slate-800 rounded-xl pl-10 pr-4 py-3 focus:ring-2 focus:ring-emerald-500 outline-none text-slate-200 font-bold" />
                </div>
              </div>
            </div>

            <button onClick={() => setShowSettings(false)} className="w-full bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold py-3 rounded-xl transition-all shadow-lg">Confirmar Ajustes</button>
          </div>
        </div>
      )}

      <main className="max-w-6xl mx-auto p-4 lg:p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-8 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {[
              { label: 'Essenciais*', val: stats.totalNeeds + stats.debtInterest + stats.debtNoInterest + stats.fixedDebts, fixed: stats.fixedNeeds + stats.fixedDebts, target: targets[CategoryType.NEED], color: 'blue', icon: CreditCardIcon },
              { label: 'Desejos', val: stats.wants + stats.fixedWants, fixed: stats.fixedWants, target: targets[CategoryType.WANT], color: 'purple', icon: PieChartIcon },
              { label: 'Reserva', val: stats.savings, fixed: 0, target: targets[CategoryType.SAVING], color: 'emerald', icon: TrendingUpIcon }
            ].map((card, idx) => {
              const isOver = card.val > card.target;
              return (
                <div key={idx} className={`glass p-6 rounded-3xl space-y-2 border-l-4 transition-all ${isOver ? 'border-red-500 shadow-lg shadow-red-900/10' : `border-${card.color}-500`}`}>
                  <div className="flex justify-between items-start">
                    <p className="text-slate-400 text-sm">{card.label}</p>
                    <card.icon className={`w-4 h-4 ${isOver ? 'text-red-500' : `text-${card.color}-500`}`} />
                  </div>
                  <p className={`text-xl font-bold ${isOver ? 'text-red-400' : ''}`}>{formatCurrency(card.val)}</p>
                  <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden flex">
                    <div className="bg-slate-500 h-full opacity-50" style={{ width: `${Math.min(100, (card.fixed / (card.target || 1)) * 100)}%` }} />
                    <div className={`${isOver ? 'bg-red-500' : `bg-${card.color}-500`} h-full`} style={{ width: `${Math.min(100, ((card.val - card.fixed) / (card.target || 1)) * 100)}%` }} />
                  </div>
                </div>
              );
            })}
          </div>

          {/* Cash Flow Projection Section */}
          <div className="glass p-6 md:p-8 rounded-3xl space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-2">
              <div className="flex items-center gap-3">
                <div className="bg-blue-500/20 p-3 rounded-2xl"><LineChartIcon className="w-6 h-6 text-blue-400" /></div>
                <div>
                  <h2 className="text-xl font-bold">Previsão 30 Dias</h2>
                  <p className="text-xs text-slate-500">Saldo projetado considerando fixos</p>
                </div>
              </div>
              <div className="bg-slate-900/80 px-4 py-2 rounded-xl border border-slate-800 flex items-center gap-4">
                 <div className="text-center">
                    <p className="text-[9px] text-slate-500 uppercase font-black">Gasto Diário Seguro</p>
                    <p className="text-sm font-black text-emerald-400">{formatCurrency(safeToSpendDaily)}</p>
                 </div>
                 <div className="w-px h-8 bg-slate-800" />
                 <div className="text-center">
                    <p className="text-[9px] text-slate-500 uppercase font-black">Próximo Salário</p>
                    <p className="text-sm font-black text-blue-400">{daysUntilPayday} dias</p>
                 </div>
              </div>
            </div>

            <div className="h-[220px] w-full mt-4">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={projectionData}>
                  <defs>
                    <linearGradient id="colorBalance" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                      <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" vertical={false} />
                  <XAxis dataKey="day" stroke="#475569" fontSize={10} tickLine={false} axisLine={false} interval={5} />
                  <YAxis stroke="#475569" fontSize={10} tickLine={false} axisLine={false} tickFormatter={(value) => `${value / 1000}k`} />
                  <Tooltip 
                    contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '12px', fontSize: '12px' }}
                    itemStyle={{ color: '#3b82f6', fontWeight: 'bold' }}
                    formatter={(value: number) => [formatCurrency(value), 'Saldo']}
                  />
                  <Area type="monotone" dataKey="balance" stroke="#3b82f6" strokeWidth={3} fillOpacity={1} fill="url(#colorBalance)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="relative overflow-hidden group">
            <div className="absolute -inset-1 bg-gradient-to-r from-emerald-500 to-blue-500 rounded-3xl blur opacity-25"></div>
            <div className="relative glass p-6 md:p-8 rounded-3xl space-y-6">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div className="flex items-center gap-3">
                  <div className="bg-emerald-500/20 p-3 rounded-2xl"><SparklesIcon className="w-6 h-6 text-emerald-400" /></div>
                  <div>
                    <h2 className="text-xl font-bold">Mentor Finmo</h2>
                    <p className="text-xs text-slate-500">Conselho inteligente e pragmático</p>
                  </div>
                </div>
                <button onClick={getMentorship} disabled={loadingAdvice} className="w-full md:w-auto bg-emerald-500 hover:bg-emerald-400 text-slate-950 font-bold py-2.5 px-6 rounded-xl transition-all">
                  {loadingAdvice ? "Analisando..." : "Pedir Mentoria"}
                </button>
              </div>
              {aiAdvice && (
                <div className={`p-6 rounded-2xl border-l-4 animate-in fade-in slide-in-from-bottom-2 ${aiAdvice.status === 'critical' ? 'bg-red-500/10 border-red-500' : 'bg-emerald-500/10 border-emerald-500'}`}>
                  <p className="text-base md:text-lg font-medium mb-4 italic text-slate-200 leading-relaxed">"{aiAdvice.message}"</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {aiAdvice.recommendations.map((rec, i) => (
                      <div key={i} className="flex items-start gap-3 bg-slate-900/50 p-3 rounded-xl border border-slate-800">
                        <ChevronRightIcon className="w-4 h-4 text-emerald-400 flex-shrink-0 mt-0.5" />
                        <span className="text-sm text-slate-300">{rec}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="lg:col-span-4 space-y-8">
          <div className="glass p-5 md:p-6 rounded-3xl sticky top-24">
            <div className="flex gap-2 p-1 bg-slate-900/50 rounded-xl mb-6">
               <button onClick={() => setFormType('expense')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'expense' ? 'bg-slate-800 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>GASTO</button>
               <button onClick={() => setFormType('fixed')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'fixed' ? 'bg-blue-500 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>FIXO</button>
               <button onClick={() => setFormType('income')} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${formType === 'income' ? 'bg-emerald-500 text-slate-950 shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}>RENDA</button>
            </div>

            <form onSubmit={handleAddTransaction} className="space-y-4">
              <input type="text" placeholder="Descrição" value={description} onChange={(e) => setDescription(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" />
              <input type="number" placeholder="Valor (MT)" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold text-slate-100" />

              {category === CategoryType.DEBT_INTEREST && formType === 'expense' && (
                <div className="space-y-1 animate-in slide-in-from-top-2">
                  <label className="text-[10px] text-red-400 uppercase font-black ml-1">Juros Inclusos (MT)</label>
                  <input type="number" placeholder="Opcional" value={interestAmount} onChange={(e) => setInterestAmount(e.target.value)} className="w-full bg-red-950/20 border border-red-900/50 rounded-xl px-4 py-3 focus:ring-2 focus:ring-red-500 outline-none transition-all font-bold text-red-400" />
                </div>
              )}

              {formType !== 'income' && (
                <div className="grid grid-cols-2 gap-2">
                    <button type="button" onClick={() => setCategory(CategoryType.NEED)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.NEED ? 'bg-blue-500/20 border-blue-500 text-blue-400 font-bold' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Necessidade</button>
                    <button type="button" onClick={() => setCategory(CategoryType.WANT)} className={`text-[10px] py-2 rounded-lg border ${category === CategoryType.WANT ? 'bg-purple-500/20 border-purple-500 text-purple-400 font-bold' : 'bg-slate-900 border-slate-800 text-slate-500'}`}>Desejo</button>
                </div>
              )}

              <div className="relative">
                <select value={subcategory} onChange={(e) => setSubcategory(e.target.value)} className="w-full bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 outline-none text-sm appearance-none focus:ring-2 focus:ring-blue-500 transition-all cursor-pointer">
                  {SUBCATEGORIES[category].map((sub) => <option key={sub} value={sub}>{sub}</option>)}
                </select>
                <ChevronRightIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 rotate-90 pointer-events-none" />
              </div>

              <button type="submit" className={`w-full font-bold py-3.5 rounded-xl transition-all shadow-lg active:scale-[0.98] ${formType === 'income' ? 'bg-emerald-500 text-slate-950' : formType === 'fixed' ? 'bg-blue-500 text-white' : 'bg-white text-slate-950'}`}>
                {formType === 'fixed' ? 'Salvar Fixo' : formType === 'income' ? 'Registrar Renda' : 'Registrar Gasto'}
              </button>
            </form>
          </div>

          <div className="glass p-5 md:p-6 rounded-3xl min-h-[300px]">
            <h3 className="text-sm font-bold mb-6 text-slate-400 uppercase tracking-widest flex items-center gap-2"><ClockIcon className="w-4 h-4" /> Atividade Recente</h3>
            <div className="space-y-3">
              {transactions.length === 0 ? (
                <div className="text-center py-20 text-slate-600 text-xs italic">Sem registros.</div>
              ) : (
                transactions.slice(0, 10).map((t) => {
                  const isInc = t.category === CategoryType.INCOME;
                  const isDebtWithInt = t.category === CategoryType.DEBT_INTEREST && t.interestAmount && t.interestAmount > 0;
                  return (
                    <div key={t.id} className={`group relative p-4 rounded-2xl border transition-all ${isInc ? 'bg-emerald-500/5 border-emerald-500/20' : isDebtWithInt ? 'bg-red-500/10 border-red-500/30' : 'bg-slate-900/50 border-transparent hover:border-slate-800'}`}>
                      <div className={`absolute left-0 top-0 bottom-0 w-1 rounded-l-full ${isInc ? 'bg-emerald-500' : CATEGORY_COLORS[t.category]}`} />
                      <div className="flex justify-between items-start">
                        <div className="min-w-0 pr-2">
                          <p className="text-sm font-bold truncate">{t.description}</p>
                          <p className="text-[10px] text-slate-500 mt-1">{t.subcategory} • {new Date(t.date).toLocaleDateString()}</p>
                          {isDebtWithInt && (
                            <div className="mt-2 p-1.5 bg-red-500/10 border border-red-500/20 rounded-lg flex items-start gap-1">
                               <InfoIcon className="w-2.5 h-2.5 text-red-400 mt-0.5 flex-shrink-0" />
                               <p className="text-[8px] font-bold text-red-400 leading-tight">JUROS: {formatCurrency(t.interestAmount!)} inclusos.</p>
                            </div>
                          )}
                        </div>
                        <div className="flex items-center gap-2">
                           <span className={`font-black text-xs ${isInc ? 'text-emerald-400' : 'text-slate-100'}`}>{isInc ? '+' : '-'}{formatCurrency(t.amount)}</span>
                           <button onClick={() => { setTransactionToDelete(t.id); setShowDeleteModal(true); }} className="p-1 text-slate-600 hover:text-red-400 transition-all"><Trash2Icon className="w-3.5 h-3.5" /></button>
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>
      </main>

      {/* Modals (Excluindo para brevidade, mantendo os necessários no componente real) */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowDeleteModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6">
            <h3 className="text-xl font-bold text-center">Apagar Registro?</h3>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowDeleteModal(false)} className="py-3 rounded-xl bg-slate-800 text-slate-300 font-bold">Voltar</button>
              <button onClick={executeDelete} className="py-3 rounded-xl bg-red-600 text-white font-bold">Apagar</button>
            </div>
          </div>
        </div>
      )}

      {showResetModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowResetModal(false)} />
          <div className="relative glass p-8 rounded-3xl max-w-sm w-full space-y-6 text-center">
             <RotateCcwIcon className="w-12 h-12 text-orange-500 mx-auto" />
            <h3 className="text-xl font-bold">Reiniciar Dados?</h3>
            <p className="text-xs text-slate-400">Esta ação não pode ser desfeita.</p>
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setShowResetModal(false)} className="py-3 rounded-xl bg-slate-800 font-bold">Cancelar</button>
              <button onClick={handleResetData} className="py-3 rounded-xl bg-orange-600 font-bold">Sim, Reset</button>
            </div>
          </div>
        </div>
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-950/90 backdrop-blur-md border-t border-slate-900 py-3 px-4 flex justify-between items-center text-[9px] tracking-widest text-slate-600 uppercase">
        <span>Finmo • {new Date().getFullYear()}</span>
        {user && <span className="flex items-center gap-1 text-emerald-500/50"><CloudCheckIcon className="w-3 h-3" /> Sincronizado</span>}
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrendingUpIcon, 
  WalletIcon, 
  CreditCardIcon, 
  PieChartIcon, 
  SparklesIcon,
  Trash2Icon,
  ChevronRightIcon,
  TagIcon,
  AlertTriangleIcon,
  XIcon,
  RotateCcwIcon,
  CalendarIcon,
  ArrowRightIcon,
  FlameIcon,
  BanknoteIcon,
  RepeatIcon,
  Settings2Icon,
  InfoIcon,
  LineChartIcon,
  ClockIcon,
  LogOutIcon,
  CloudCheckIcon,
  CloudIcon
} from 'lucide-react';
import { 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  AreaChart,
  Area
} from 'recharts';
import { CategoryType, Transaction, BudgetStats, AIAdvice, FixedExpense } from './types';
import { CATEGORY_LABELS, CATEGORY_COLORS, SUBCATEGORIES, formatCurrency } from './constants';
import { getFinancialAdvice } from './services/geminiService';

interface User {
  name: string;
  email: string;
  picture: string;
}

const App: React.FC = () => {
  // Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('finmo_user');
    return saved ? JSON.parse(saved) : null;
  });

  // Persistence states
  const [baseIncome, setBaseIncome] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_income');
    return saved ? Number(saved) : 30000;
  });

  const [payday, setPayday] = useState<number>(() => {
    const saved = localStorage.getItem('finmo_payday');
    return saved ? Number(saved) : 1;
  });

  const [fixedExpenses, setFixedExpenses] = useState<FixedExpense[]>(() => {
    const saved = localStorage.getItem('finmo_fixed');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('finmo_transactions');
    try {
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Erro ao carregar transações:", e);
      return [];
    }
  });

  // UI / Form states
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [interestAmount, setInterestAmount] = useState('');
  const [formType, setFormType] = useState<'expense' | 'income' | 'fixed'>('expense');
  const [category, setCategory] = useState<CategoryType>(CategoryType.NEED);
  const [subcategory, setSubcategory] = useState<string>(SUBCATEGORIES[CategoryType.NEED][0]);
  const [dueDate, setDueDate] = useState('');
  const [aiAdvice, setAiAdvice] = useState<AIAdvice | null>(null);
  const [loadingAdvice, setLoadingAdvice] = useState(false);
  const [showFixedManager, setShowFixedManager] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [transactionToDelete, setTransactionToDelete] = useState<string | null>(null);
  const [showResetModal, setShowResetModal] = useState(false);

  // Sync with LocalStorage
  useEffect(() => localStorage.setItem('finmo_income', baseIncome.toString()), [baseIncome]);
  useEffect(() => localStorage.setItem('finmo_payday', payday.toString()), [payday]);
  useEffect(() => localStorage.setItem('finmo_fixed', JSON.stringify(fixedExpenses)), [fixedExpenses]);
  useEffect(() => localStorage.setItem('finmo_transactions', JSON.stringify(transactions)), [transactions]);
  useEffect(() => {
    if (user) localStorage.setItem('finmo_user', JSON.stringify(user));
    else localStorage.removeItem('finmo_user');
  }, [user]);

  // Google Auth Initialization
  useEffect(() => {
    const handleCredentialResponse = (response: any) => {
      try {
        const payload = JSON.parse(atob(response.credential.split('.')[1]));
        const userData: User = {
          name: payload.name,
          email: payload.email,
          picture: payload.picture
        };
        setUser(userData);
      } catch (error) {
        console.error("Erro ao decodificar token do Google", error);
      }
    };

    // Fix: Using type assertion to access 'google' on window to avoid TypeScript error
    const google = (window as any).google;

    if (google) {
      google.accounts.id.initialize({
        client_id: "YOUR_GOOGLE_CLIENT_ID.apps.googleusercontent.com", // Em produção o usuário forneceria isso
        callback: handleCredentialResponse,
        auto_select: false
      });

      if (!user) {
        google.accounts.id.renderButton(
          document.getElementById("google-login-btn"),
          { theme: "outline", size: "medium", type: "standard", shape: "pill", text: "signin_with", logo_alignment: "left" }
        );
      }
    }
  }, [user]);

  const handleLogout = () => {
    setUser(null);
    window.location.reload(); // Recarregar para resetar instâncias se necessário
  };

  // Adjust category based on form type
  useEffect(() => {
    if (formType === 'income') setCategory(CategoryType.INCOME);
    else if (formType === 'fixed') setCategory(CategoryType.NEED);
    else if (category === CategoryType.INCOME) setCategory(CategoryType.NEED);
  }, [formType]);

  useEffect(() => {
    setSubcategory(SUBCATEGORIES[category][0]);
    if (category !== CategoryType.DEBT_INTEREST && category !== CategoryType.DEBT_NO_INTEREST) {
      setDueDate('');
      setInterestAmount('');
    }
  }, [category]);

  const stats = useMemo<BudgetStats>(() => {
    const s: BudgetStats = { 
      baseIncome, 
      variableIncome: 0, 
      totalIncome: 0,
      fixedNeeds: 0,
      variableNeeds: 0,
      totalNeeds: 0,
      wants: 0,
      fixedWants: 0,
      savings: 0, 
      debtInterest: 0, 
      debtNoInterest: 0, 
      fixedDebts: 0,
      totalSpent: 0 
    };

    fixedExpenses.forEach(fe => {
      if (fe.category === CategoryType.NEED) s.fixedNeeds += fe.amount;
      if (fe.category === CategoryType.WANT) s.fixedWants += fe.amount;
      if (fe.category === CategoryType.DEBT_NO_INTEREST) s.fixedDebts += fe.amount;
    });

    transactions.forEach(t => {
      if (t.category === CategoryType.INCOME) {
        s.variableIncome += t.amount;
      } else {
        if (t.category === CategoryType.NEED) s.variableNeeds += t.amount;
        if (t.category === CategoryType.WANT) s.wants += t.amount;
        if (t.category === CategoryType.SAVING) s.savings += t.amount;
        if (t.category === CategoryType.DEBT_INTEREST) s.debtInterest += t.amount;
        if (t.category === CategoryType.DEBT_NO_INTEREST) s.debtNoInterest += t.amount;
      }
    });

    s.totalIncome = s.baseIncome + s.variableIncome;
    s.totalNeeds = s.fixedNeeds + s.variableNeeds;
    s.totalSpent = s.totalNeeds + s.wants + s.fixedWants + s.savings + s.debtInterest + s.debtNoInterest + s.fixedDebts;

    return s;
  }, [transactions, baseIncome, fixedExpenses]);

  // Cash Flow Projection
  const projectionData = useMemo(() => {
    const days = 30;
    const data = [];
    let currentBalance = stats.totalIncome - stats.totalSpent;
    const totalFixedPerMonth = stats.fixedNeeds + stats.fixedWants + stats.fixedDebts;
    const today = new Date();

    for (let i = 0; i <= days; i++) {
      const date = new Date(today);
      date.setDate(today.getDate() + i);
      const dayOfMonth = date.getDate();
      if (dayOfMonth === payday && i > 0) {
        currentBalance += baseIncome;
        currentBalance -= totalFixedPerMonth;
      }
      data.push({
        day: date.toLocaleDateString('pt-MZ', { day: '2-digit', month: 'short' }),
        balance: Math.max(0, currentBalance),
      });
    }
    return data;
  }, [stats, payday, baseIncome]);

  const targets = {
    [CategoryType.NEED]: stats.totalIncome * 0.5,
    [CategoryType.WANT]: stats.totalIncome * 0.3,
    [CategoryType.SAVING]: stats.totalIncome * 0.2,
  };

  const handleAddTransaction = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;
    const val = parseFloat(amount);

    if (formType === 'fixed') {
      const newFixed: FixedExpense = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        category: category as any
      };
      setFixedExpenses([...fixedExpenses, newFixed]);
    } else {
      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        description,
        amount: val,
        interestAmount: interestAmount ? parseFloat(interestAmount) : undefined,
        category,
        subcategory,
        date: new Date().toISOString(),
        dueDate: isDebt(category) ? dueDate : undefined
      };
      setTransactions([newTransaction, ...transactions]);
    }

    setDescription('');
    setAmount('');
    setInterestAmount('');
    setDueDate('');
  };

  const executeDelete = () => {
    if (transactionToDelete) {
      setTransactions(transactions.filter(t => t.id !== transactionToDelete));
      setTransactionToDelete(null);
      setShowDeleteModal(false);
    }
  };

  const handleResetData = () => {
    setBaseIncome(30000);
    setPayday(1);
    setFixedExpenses([]);
    setTransactions([]);
    setAiAdvice(null);
    setShowResetModal(false);
  };

  const removeFixed = (id: string) => {
    setFixedExpenses(fixedExpenses.filter(fe => fe.id !== id));
  };

  const getMentorship = async () => {
    setLoadingAdvice(true);
    const advice = await getFinancialAdvice(stats, transactions, stats.totalIncome);
    setAiAdvice(advice);
    setLoadingAdvice(false);
  };

  const isDebt = (cat: CategoryType) => cat === CategoryType.DEBT_INTEREST || cat === CategoryType.DEBT_NO_INTEREST;

  const daysUntilPayday = useMemo(() => {
    const today = new Date();
    const currentDay = today.getDate();
    if (currentDay < payday) return payday - currentDay;
    const lastDayOfMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();
    return (lastDayOfMonth - currentDay) + payday;
  }, [payday]);

  const safeToSpendDaily = useMemo(() => {
    const currentBalance = stats.totalIncome - stats.totalSpent;
    return Math.max(0, currentBalance / (daysUntilPayday || 1));
  }, [stats, daysUntilPayday]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 pb-20">
      <header className="sticky top-0 z-50 glass border-b border-slate-800 px-4 md:px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
